    private val adhyayaTwoShlokas = listOf(
        Shloka(
            number = 1,
            sanskrit = "सञ्जय उवाच — तं तथा कृपयाविष्टमश्रुपूर्णाकुलेक्षणम्। विषीदन्तमिदं वाक्यमुवाच मधुसूदनः॥ 2.1॥",
            hindiMeaning = "संजय धृतराष्ट्र से कहते हैं कि अर्जुन करुणा और मोह से ग्रसित होकर शोकमग्न हो चुका था। उसके नेत्र आँसुओं से भरे थे और उसका मन अत्यंत विचलित था। युद्धभूमि में खड़ा होकर भी वह अपने कर्तव्य का निर्णय नहीं कर पा रहा था। वह अपने बंधु-बांधवों के वध की कल्पना से द्रवित हो उठा था। उसकी स्थिति इतनी दयनीय हो गई कि उसका शरीर शिथिल हो गया और उसका आत्मबल टूटने लगा। यह देखकर भगवान श्रीकृष्ण, जो मधुसूदन कहलाते हैं, अर्जुन को शिक्षा देने लगे। यही गीता के उपदेश का प्रारम्भिक क्षण है जहाँ से धर्म और अध्यात्म का गूढ़ रहस्य उद्घाटित होता है।",
            englishMeaning = "Sanjaya said: Seeing Arjuna overwhelmed with compassion, his eyes full of tears and his mind distressed, Madhusudana (Krishna) spoke these words."
        ),

        Shloka(
            number = 2,
            sanskrit = "श्रीभगवानुवाच — कुतस्त्वा कश्मलमिदं विषमे समुपस्थितम्। अनार्यजुष्टमस्वर्ग्यमकीर्तिकरमर्जुन॥ 2.2॥",
            hindiMeaning = "श्रीकृष्ण अर्जुन को डांटते हुए कहते हैं कि यह दुर्बलता और मोह तुझ पर इस कठिन समय में कैसे छा गया? यह तेरे कुल और धर्म के विपरीत है। यह न तो आर्य पुरुषों के योग्य है, न इससे स्वर्ग की प्राप्ति होती है, और न ही इससे यश मिलता है। यह केवल अपयश और लज्जा का कारण बनेगा। भगवान यहाँ अर्जुन को याद दिला रहे हैं कि वह एक क्षत्रिय है और युद्ध के समय दुर्बलता दिखाना उसकी प्रकृति के विपरीत है। यह मोह उसकी कीर्ति को नष्ट करेगा और उसके धर्म का अपमान होगा। इसलिए उसे इस विषाद को त्यागकर अपने कर्तव्य की ओर बढ़ना चाहिए।",
            englishMeaning = "The Lord said: From where has this weakness come upon you in this crisis? It is unworthy of an honorable man, it does not lead to heaven, and it brings disgrace."
        ),

        Shloka(
            number = 3,
        sanskrit = "क्लैब्यं मा स्म गमः पार्थ नैतत्त्वय्युपपद्यते। क्षुद्रं हृदयदौर्बल्यं त्यक्त्वोत्तिष्ठ परन्तप॥ 2.3॥",
        hindiMeaning = "कृष्ण अर्जुन को झकझोरते हुए कहते हैं कि हे पार्थ, तू इस नपुंसकता में मत पड़। यह तेरे योग्य नहीं है। यह हृदय की दुर्बलता अत्यंत क्षुद्र है। इसे त्यागकर तू खड़ा हो और अपने शत्रुओं का दमन कर। भगवान यहाँ अर्जुन को स्मरण कराते हैं कि उसकी वास्तविक पहचान एक वीर योद्धा की है। क्षत्रिय का धर्म है कि वह अधर्म के विरुद्ध युद्ध करे। यदि वह इस समय विचलित होगा तो धर्म का पतन होगा और उसका जीवन व्यर्थ हो जाएगा। इसलिए उसे इस दुर्बलता को छोड़कर साहसपूर्वक युद्ध करना चाहिए।",
        englishMeaning = "Do not yield to this impotence, O Partha. It does not suit you. Cast off this petty weakness of heart and arise, O scorcher of foes."
    ),

    Shloka(
    number = 4,
    sanskrit = "अर्जुन उवाच — कथं भीष्ममहं सङ्ख्ये द्रोणं च मधुसूदन। इषुभिः प्रतियोत्स्यामि पूजार्हावरिसूदन॥ 2.4॥",
    hindiMeaning = "अर्जुन भगवान से कहता है कि हे मधुसूदन, मैं भीष्म पितामह और आचार्य द्रोण जैसे पूजनीय गुरुओं पर बाण कैसे चला सकता हूँ? ये दोनों मेरे जीवन में सदैव सम्माननीय रहे हैं और उनके चरणों में मैंने शिक्षा पाई है। उनके विरुद्ध शस्त्र उठाना मुझे धर्मविरोधी प्रतीत होता है। अर्जुन का हृदय गुरु और बड़ों के प्रति आदर से भरा हुआ है। युद्धभूमि में खड़े होकर भी उसका विवेक यह स्वीकार नहीं करता कि अपने पूजनीयजनों के प्राण लेना उचित होगा। यह दुविधा अर्जुन के मोह का मुख्य कारण है।",
    englishMeaning = "Arjuna said: O Madhusudana, how can I fight against Bhishma and Drona with arrows in battle, for they are worthy of worship, O destroyer of enemies?"
    ),

    Shloka(
    number = 5,
    sanskrit = "गुरूनहत्वा हि महानुभावान्श्रेयो भोक्तुं भैक्ष्यमपीह लोके। हत्वार्थकामांस्तु गुरुनिहैव भुञ्जीय भोगान् रुधिरप्रदिग्धान्॥ 2.5॥",
    hindiMeaning = "अर्जुन कहता है कि अपने महानुभाव गुरुजनों को न मारना ही उत्तम है। भले ही मुझे इस संसार में भिक्षा लेकर जीना पड़े, परन्तु उनके वध से प्राप्त राज्य और सुख मेरे लिए रक्त से सने होंगे। ऐसा भोग मुझे पाप का अनुभव कराएगा। अर्जुन मानता है कि गुरुजनों का वध करके मिलने वाला राज्य न केवल अधर्मपूर्ण होगा बल्कि उसके अंतःकरण को भी छलनी कर देगा। युद्ध के बाद का जीवन उसे ग्लानि और अपराधबोध से भर देगा। इसलिए वह मानता है कि साधारण जीवन भी युद्ध से प्राप्त भोग-विलास से श्रेष्ठ है।",
    englishMeaning = "It is better to live in this world by begging than to slay these great souls, my teachers. If I kill them, my enjoyments will be tainted with their blood."
    ),

    Shloka(
    number = 6,
    sanskrit = "न चैतद्विद्मः कतरन्नो गरीयो यद्वा जयेम यदि वा नो जयेयुः। यानेव हत्वा न जिजीविषामस्तेऽवस्थिताः प्रमुखे धार्तराष्ट्राः॥ 2.6॥",
    hindiMeaning = "अर्जुन कहता है कि हम यह भी नहीं जानते कि युद्ध करने पर हमारे लिए क्या श्रेष्ठ होगा – विजय या पराजय। यदि हम विजयी भी हो जाएँ तो भी हमें आनंद नहीं होगा क्योंकि हमें उन्हीं को मारना होगा जिनके बिना जीना हमें असह्य लगता है। हमारे सामने खड़े ये धृतराष्ट्र के पुत्र जिन्हें मारकर जीने की इच्छा नहीं है, यही दुविधा का कारण हैं। यह श्लोक अर्जुन की गहन उलझन को दर्शाता है। वह युद्ध के परिणाम से भयभीत है और उसे यह समझ नहीं आ रहा कि किसे श्रेष्ठ माना जाए। यही मोह उसकी दृष्टि को ढक लेता है।",
    englishMeaning = "We do not know what is better for us—whether we conquer them or they conquer us. Even after victory, we would not wish to live after slaying the sons of Dhritarashtra who stand before us."
    ),

    Shloka(
    number = 7,
    sanskrit = "कार्पण्यदोषोपहतस्वभावः पृच्छामि त्वां धर्मसंमूढचेताः। यच्छ्रेयः स्यान्निश्चितं ब्रूहि तन्मे शिष्यस्तेऽहं शाधि मां त्वां प्रपन्नम्॥ 2.7॥",
    hindiMeaning = "अर्जुन कहता है कि मैं कायरता से ग्रस्त होकर अपने स्वभाव को खो बैठा हूँ। मेरा चित्त धर्म के विषय में पूर्ण रूप से भ्रमित हो चुका है। इसलिए हे कृष्ण, मैं आपसे निवेदन करता हूँ कि मेरे लिए जो निश्चित रूप से श्रेयस्कर है, उसे बताइए। मैं आपके शिष्य के रूप में आपकी शरण में आया हूँ। कृपया मुझे शिक्षा दीजिए और मेरा मार्गदर्शन कीजिए। यहाँ अर्जुन अपने अहंकार को छोड़कर गुरु-शिष्य संबंध स्थापित करता है। यह क्षण गीता के उपदेश की वास्तविक शुरुआत का प्रतीक है।",
    englishMeaning = "My nature is overpowered by weakness, and my mind is confused about dharma. I ask you to tell me what is best for me. I am your disciple, surrendered to you. Please instruct me."
    ),

    Shloka(
    number = 8,
    sanskrit = "न हि प्रपश्यामि ममापनुद्याद्यच्छोकमुच्छोषणमिन्द्रियाणाम्। अवाप्य भूमावसपत्नमृद्धं राज्यं सुराणामपि चाधिपत्यम्॥ 2.8॥",
    hindiMeaning = "अर्जुन कहता है कि मुझे ऐसा कोई उपाय दिखाई नहीं देता जिससे यह शोक दूर हो सके, जो मेरी इंद्रियों को सुखा डाल रहा है। यदि मुझे इस पृथ्वी पर निष्कंटक राज्य भी मिल जाए और देवताओं का आधिपत्य भी प्राप्त हो जाए, तब भी मेरे शोक का निवारण नहीं हो सकता। यह श्लोक अर्जुन की गहन मानसिक पीड़ा को प्रकट करता है। उसका हृदय मोह और दुःख से इतना बोझिल है कि भौतिक सुख-संपत्ति भी उसे शांति नहीं दे सकती। यह उसकी स्थिति की गंभीरता को दर्शाता है। अर्जुन का मन पूरी तरह भ्रम और दुविधा में फँस चुका है।",
    englishMeaning = "I do not see any means that can remove my sorrow, which is drying up my senses. Even if I were to gain an unrivalled kingdom on earth or lordship over the gods, it would not drive away my grief."
    ),

    Shloka(
    number = 9,
    sanskrit = "सञ्जय उवाच — एवमुक्त्वा हृषीकेशं गुडाकेशः परन्तप। न योत्स्य इति गोविन्दमुक्त्वा तूष्णीं बभूव ह॥ 2.9॥",
    hindiMeaning = "संजय कहते हैं कि इस प्रकार गुडाकेश अर्जुन, जो शत्रुओं का दमन करने वाला है, हृषीकेश श्रीकृष्ण से कहकर बैठ गया कि वह युद्ध नहीं करेगा। अर्जुन ने अपनी दुर्बलता और मोह को सामने रखकर स्पष्ट कर दिया कि उसका मन युद्ध करने के लिए तैयार नहीं है। यह उसकी आत्मिक हार थी। अब वह मौन होकर बैठ गया। यह स्थिति अर्जुन की दुविधा और निराशा का चरम रूप है। यही कारण है कि अब कृष्ण को गहन अध्यात्मिक शिक्षा देनी आवश्यक हो जाती है।",
    englishMeaning = "Sanjaya said: Having spoken thus to Hrishikesha, Arjuna, the conqueror of sleep, declared to Govinda, 'I shall not fight,' and fell silent."
    ),

    Shloka(
    number = 10,
    sanskrit = "तमुवाच हृषीकेशः प्रहसन्निव भारत। सेनयोरुभयोर्मध्ये विषीदन्तमिदं वचः॥ 2.10॥",
    hindiMeaning = "संजय कहते हैं कि दोनों सेनाओं के बीच खड़े हुए विषादग्रस्त अर्जुन से हृषीकेश श्रीकृष्ण ने हँसते हुए यह वचन कहा। कृष्ण की यह मुस्कान करुणा और आत्मविश्वास से भरी थी। वह अर्जुन की कमजोरी और मोह को देखकर उसे धैर्य और शिक्षा देने के लिए तत्पर हो गए। यह दृश्य यह दर्शाता है कि भगवान अपने भक्त के विषाद में भी उसे सही मार्ग दिखाने का संकल्प रखते हैं। अब गीता के वास्तविक उपदेश का प्रारम्भ होने वाला है। यही वह क्षण है जहाँ से अर्जुन का अज्ञान दूर कर उसे धर्म और आत्मज्ञान की ओर ले जाया जाएगा।",
    englishMeaning = "O Bharata, Hrishikesha, smiling as it were, spoke these words to the grief-stricken Arjuna in the midst of both armies."
    ) ,

    Shloka(
    number = 11,
    sanskrit = "श्रीभगवानुवाच — अशोच्यानन्वशोचस्त्वं प्रज्ञावादांश्च भाषसे। गतासूनगतासूंश्च नानुशोचन्ति पण्डिताः॥ 2.11॥",
    hindiMeaning = "भगवान श्रीकृष्ण अर्जुन से कहते हैं कि तू जिनके लिए शोक कर रहा है वे शोक के योग्य नहीं हैं। तू ज्ञान की बातें करता है पर वास्तव में तू अज्ञान से ग्रसित है। जो ज्ञानी पुरुष होते हैं वे न जीवित के लिए शोक करते हैं और न मृत के लिए। मृत्यु और जन्म सदा चलने वाली प्रक्रिया है। आत्मा न जन्म लेती है न मरती है, यह सत्य को समझने वाला कभी शोकग्रस्त नहीं होता। कृष्ण अर्जुन को यह समझाना चाहते हैं कि उसका दुःख अज्ञान का परिणाम है। यदि उसे आत्मा का ज्ञान हो तो शोक का कोई स्थान ही नहीं रहेगा।",
    englishMeaning = "The Lord said: You grieve for those who should not be grieved for, and yet speak words of wisdom. The wise grieve neither for the living nor for the dead."
    ),

    Shloka(
    number = 12,
    sanskrit = "न त्वेवाहं जातु नासं न त्वं नेमे जनाधिपाः। न चैव न भविष्यामः सर्वे वयमतः परम्॥ 2.12॥",
    hindiMeaning = "कृष्ण कहते हैं कि न कभी ऐसा समय था जब मैं नहीं था, न तू नहीं था और न ये राजपुरुष। भविष्य में भी हम सब अस्तित्व से लुप्त नहीं होंगे। आत्मा शाश्वत है और कभी नष्ट नहीं होती। शरीर बदलते रहते हैं, पर आत्मा निरंतर बनी रहती है। यह सत्य जानकर मनुष्य मृत्यु से भयभीत नहीं होता। अर्जुन का शोक इस अज्ञान पर आधारित है कि मृत्यु ही अंत है। जबकि वास्तविकता यह है कि आत्मा कभी नष्ट नहीं होती और न ही उसका जन्म होता है।",
    englishMeaning = "Never was there a time when I did not exist, nor you, nor all these kings. Nor in the future shall any of us cease to be."
    ),

    Shloka(
    number = 13,
    sanskrit = "देहिनोऽस्मिन्यथा देहे कौमारं यौवनं जरा। तथा देहान्तरप्राप्तिर्धीरस्तत्र न मुह्यति॥ 2.13॥",
    hindiMeaning = "श्रीकृष्ण कहते हैं कि जैसे इस शरीर में आत्मा बाल्यावस्था से यौवन और वृद्धावस्था तक जाती है, वैसे ही मृत्यु के बाद आत्मा नया शरीर धारण करती है। जो विवेकशील है वह इस सत्य से मोहित नहीं होता। शरीर नश्वर है पर आत्मा अमर है। यह परिवर्तन स्वाभाविक है और इसे स्वीकार करना ही वास्तविक ज्ञान है। अर्जुन को यह समझना चाहिए कि देह का नाश होना केवल एक परिवर्तन है। आत्मा सदा बनी रहती है, इसलिए प्रियजनों की मृत्यु पर अत्यधिक शोक करना उचित नहीं है।",
    englishMeaning = "Just as the soul passes through childhood, youth, and old age in this body, so also it passes into another body after death. The wise are not deluded by this."
    ),

    Shloka(
    number = 14,
    sanskrit = "मात्रास्पर्शास्तु कौन्तेय शीतोष्णसुखदुःखदाः। आगमापायिनोऽनित्यास्तांस्तितिक्षस्व भारत॥",
    hindiMeaning = "कृष्ण कहते हैं कि हे कौन्तेय, इन्द्रियों और विषयों के संपर्क से ही शीत-उष्ण, सुख-दुःख उत्पन्न होते हैं। ये नित्य नहीं हैं, ये आते हैं और चले जाते हैं। इसलिए इन्हें सहन करना चाहिए। जो मनुष्य इनके आगमन और प्रस्थान से विचलित नहीं होता वही धैर्यवान कहलाता है। जीवन में सुख और दुःख दोनों ही आते-जाते रहते हैं। इनसे परे होकर स्थिरचित्त रहना ही योग है। अर्जुन को सिखाया जा रहा है कि वह सुख-दुःख की अस्थिरता से ऊपर उठकर अपने धर्म का पालन करे।",
    englishMeaning = "O son of Kunti, contacts with the senses cause heat and cold, pleasure and pain. They come and go; they are impermanent. Endure them bravely, O Bharata."
    ),

    Shloka(
    number = 15,
    sanskrit = "यं हि न व्यथयन्त्येते पुरुषं पुरुषर्षभ। समदुःखसुखं धीरं सोऽमृतत्वाय कल्पते॥",
    hindiMeaning = "कृष्ण कहते हैं कि जिसे सुख और दुःख विचलित नहीं करते, जो स्थिर और धैर्यवान रहता है, वही अमरत्व के योग्य बनता है। ऐसा व्यक्ति आत्मज्ञान की प्राप्ति कर मोक्ष को पाता है। जीवन में स्थिरता और धैर्य ही सबसे बड़ी शक्ति है। सुख-दुःख का समान भाव से सामना करने वाला मनुष्य ही सच्चा ज्ञानी है। अर्जुन को यह संदेश दिया जा रहा है कि यदि वह युद्ध में स्थिरचित्त रहेगा तो उसे आत्मज्ञान की प्राप्ति होगी। यही मार्ग मुक्ति की ओर ले जाता है।",
    englishMeaning = "That person whom these dualities of pleasure and pain do not disturb, O best among men, who remains steady and firm, is fit for immortality."
    ),

    Shloka(
    number = 16,
    sanskrit = "नासतो विद्यते भावो नाभावो विद्यते सतः। उभयोरपि दृष्टोऽन्तस्त्वनयोस्तत्त्वदर्शिभिः॥",
    hindiMeaning = "कृष्ण कहते हैं कि असत् (असत्य, नश्वर) का कभी अस्तित्व नहीं होता और सत् (सत्य, शाश्वत) का कभी अभाव नहीं होता। तत्वदर्शी ऋषियों ने दोनों का अंतर भली-भाँति समझ लिया है। असत्य चीज़ें जैसे शरीर, भौतिक वस्तुएँ आदि नाशवान हैं। सत्य, अर्थात आत्मा और परमात्मा, शाश्वत हैं। यह ज्ञान ही वास्तविक विवेक है। अर्जुन को यह जानना चाहिए कि उसका शोक केवल नाशवान शरीर के लिए है, आत्मा के लिए नहीं।",
    englishMeaning = "The unreal has no existence, and the real never ceases to be. The seers of truth have concluded this about both."
    ),

    Shloka(
    number = 17,
    sanskrit = "अविनाशि तु तद्विद्धि येन सर्वमिदं ततम्। विनाशमव्ययस्यास्य न कश्चित्कर्तुमर्हति॥",
    hindiMeaning = "भगवान कहते हैं कि जो आत्मा से सब जगह व्यापी है उसे अविनाशी समझ। वह शाश्वत और अजर है। उसका कभी नाश नहीं हो सकता। कोई भी शक्ति आत्मा का विनाश नहीं कर सकती। देह का नाश होता है लेकिन आत्मा का नहीं। यह ज्ञान मनुष्य को निर्भय बना देता है। अर्जुन को यह समझना चाहिए कि वह जिनके वध की कल्पना कर रहा है, वास्तव में उनकी आत्मा का वध करना असंभव है।",
    englishMeaning = "Know that which pervades the entire body to be indestructible. No one can destroy that imperishable soul."
    ),

    Shloka(
    number = 18,
    sanskrit = "अन्तवन्त इमे देहा नित्यस्योक्ताः शरीरिणः। अनाशिनोऽप्रमेयस्य तस्माद्युध्यस्व भारत॥",
    hindiMeaning = "कृष्ण कहते हैं कि ये शरीर नाशवान हैं पर आत्मा सदा रहने वाली और अपरिमेय है। शरीर का अंत निश्चित है लेकिन आत्मा कभी समाप्त नहीं होती। इसलिए हे भरतवंशी, तू युद्ध कर। देह नष्ट होती है पर आत्मा अविनाशी है। युद्ध में यदि शरीर नष्ट भी हो जाए तो आत्मा को कुछ नहीं होता। इसलिए धर्म पालन हेतु युद्ध करना ही उचित है। अर्जुन का मोह केवल शरीर तक सीमित है, जबकि उसे आत्मा का विचार करना चाहिए।",
    englishMeaning = "These bodies of the eternal, indestructible soul are said to be perishable. Therefore, O Bharata, fight!"
    ),

    Shloka(
    number = 19,
    sanskrit = "य एनं वेत्ति हन्तारं यश्चैनं मन्यते हतम्। उभौ तौ न विजानीतो नायं हन्ति न हन्यते॥",
    hindiMeaning = "कृष्ण कहते हैं कि जो आत्मा को मारने वाला समझता है या जो आत्मा को मरा हुआ मानता है, दोनों ही अज्ञानी हैं। आत्मा न मारता है और न मारा जा सकता है। आत्मा जन्म और मृत्यु से परे है। यह अज्ञान ही है जो मनुष्य को भ्रम में डालता है कि कोई किसी को मारता है। वस्तुतः देह का नाश होता है, आत्मा तो शाश्वत है। अर्जुन को इस अज्ञान से ऊपर उठना होगा।",
    englishMeaning = "He who thinks the soul kills or is killed, both do not know. The soul kills not, nor is it killed."
    ),

    Shloka(
    number = 20,
    sanskrit = "न जायते म्रियते वा कदाचि‍न् नायं भूत्वा भविता वा न भूयः। अजो नित्यः शाश्वतोऽयं पुराणो न हन्यते हन्यमाने शरीरे॥ 2.20॥",
    hindiMeaning = "कृष्ण कहते हैं कि आत्मा न कभी जन्म लेती है और न कभी मरती है। वह न कभी उत्पन्न होती है और न कभी नष्ट होती है। वह अजन्मा, नित्य, शाश्वत और पुरातन है। शरीर के नष्ट होने पर भी आत्मा का नाश नहीं होता। आत्मा की यह शाश्वतता ही जीवन का सत्य है। जो इस सत्य को जानता है वह मृत्यु से भयभीत नहीं होता। अर्जुन को यह समझना आवश्यक है कि आत्मा का वध असंभव है, इसलिए उसे युद्ध से विचलित नहीं होना चाहिए।",
    englishMeaning = "The soul is never born, nor does it die. It has neither come into being nor will it ever cease to be. It is unborn, eternal, everlasting, and ancient. It is not slain when the body is slain."
    ),
    Shloka(
    number = 21,
    sanskrit = "वेदाविनाशिनं नित्यं य एनमजमव्ययम्। कथं स पुरुषः पार्थ कं घातयति हन्ति कम्॥ ",
    hindiMeaning = "जो व्यक्ति यह भलीभाँति जान लेता है कि आत्मा न तो कभी जन्म लेती है और न ही कभी मरती है, वह अविनाशी और सनातन है, उसे कोई नष्ट नहीं कर सकता – वह कभी किसी को मार नहीं सकता और न ही किसी से मरवाने का कारण बन सकता है। भगवान यहाँ यह शिक्षा दे रहे हैं कि वास्तविकता में वध और हिंसा केवल शरीर तक सीमित है, आत्मा पर इसका कोई प्रभाव नहीं पड़ता। ज्ञानी व्यक्ति जब इस शाश्वत सत्य को समझ लेता है तो उसका दृष्टिकोण बदल जाता है। उसके लिए किसी की मृत्यु या हत्या का प्रश्न निरर्थक हो जाता है, क्योंकि आत्मा अमर है और केवल शरीर परिवर्तन करता है। अर्जुन को यह समझाने का तात्पर्य यह है कि तू अपने बंधु-बांधवों को मारने का दोषी नहीं होगा, क्योंकि तू केवल शरीर का नाश करेगा, आत्मा का नहीं। यही ज्ञान अर्जुन को शोक और मोह से मुक्त करेगा।",
    englishMeaning = "One who knows the soul to be eternal, unborn, and indestructible understands that no one can slay or be slain. Killing pertains only to the body, never to the soul."
    ),

    Shloka(
    number = 22,
    sanskrit = "वासांसि जीर्णानि यथा विहाय नवानि गृह्णाति नरोऽपराणि। तथा शरीराणि विहाय जीर्णा न्यन्यानि संयाति नवानि देही॥",
    hindiMeaning = "भगवान आत्मा की तुलना वस्त्र से करते हैं। जैसे मनुष्य पुराने, जीर्ण वस्त्र को त्यागकर नए वस्त्र धारण करता है, वैसे ही आत्मा पुराने शरीर को त्यागकर नया शरीर धारण करती है। इस उपमा से स्पष्ट है कि शरीर केवल आत्मा का बाहरी आवरण है, आत्मा का वास्तविक स्वरूप इस परिवर्तन से अछूता रहता है। मृत्यु वस्तुतः वस्त्र बदलने के समान है, न कि अस्तित्व का अंत। यह दृष्टिकोण अर्जुन को मृत्यु के भय और शोक से ऊपर उठाता है। आत्मा वस्त्र बदलते समय कभी प्रभावित नहीं होती, केवल बाहरी रूप बदलता है। इस ज्ञान से मनुष्य का मोह समाप्त हो जाता है।",
    englishMeaning = "As a person discards worn-out clothes and puts on new ones, so the soul discards old bodies and takes on new ones. Death is merely a change of coverings, not the end."
    ),

    Shloka(
    number = 23,
    sanskrit = "नैनं छिन्दन्ति शस्त्राणि नैनं दहति पावकः। न चैनं क्लेदयन्त्यापो न शोषयति मारुतः॥ ",
    hindiMeaning = "आत्मा की अमरता को स्पष्ट करते हुए भगवान कहते हैं कि आत्मा को शस्त्र काट नहीं सकते, अग्नि जला नहीं सकती, जल गला नहीं सकता और वायु सुखा नहीं सकती। अर्थात् कोई भी भौतिक शक्ति आत्मा को नष्ट नहीं कर सकती। शरीर पर जो भी प्रभाव पड़ता है, वह आत्मा को स्पर्श तक नहीं करता। आत्मा सदा शुद्ध, अविनाशी और शाश्वत रहती है। जो मनुष्य इस सत्य को समझ लेता है, वह निर्भय और संतुलित रहता है। अर्जुन को यह सिखाया जा रहा है कि युद्ध में चाहे शस्त्रों से शरीर का विनाश हो, आत्मा को कुछ भी नहीं होगा।",
    englishMeaning = "Weapons cannot cut the soul, fire cannot burn it, water cannot wet it, and wind cannot dry it. The soul remains beyond all material harm."
    ),

    Shloka(
    number = 24,
    sanskrit = "अच्छेद्योऽयमदाह्योऽयमक्लेद्योऽशोष्य एव च। नित्यः सर्वगतः स्थाणुरचलोऽयं सनातनः॥",
    hindiMeaning = "भगवान आत्मा के गुणों का विस्तार से वर्णन करते हैं – आत्मा अछेद्य है, अर्थात इसे काटा नहीं जा सकता। यह अदाह्य है, यानी इसे जलाया नहीं जा सकता। यह अक्लेद्य है, अर्थात इसे गीला नहीं किया जा सकता, और अशोष्य है, यानी इसे सुखाया नहीं जा सकता। आत्मा नित्य, सर्वव्यापी, स्थिर, अचल और सनातन है। यह संसार की किसी भी परिस्थिति से प्रभावित नहीं होती। जो इस सत्य को समझ लेता है वह जीवन की अस्थिरताओं से ऊपर उठ जाता है। अर्जुन के लिए यह शिक्षा आवश्यक है ताकि वह शरीर और आत्मा का भेद समझ सके।",
    englishMeaning = "The soul cannot be cut, burned, wetted, or dried. It is eternal, all-pervading, unchanging, and everlasting."
    ),

    Shloka(
    number = 25,
    sanskrit = "अव्यक्तोऽयमचिन्त्योऽयमविकार्योऽयमुच्यते। तस्मादेवं विदित्वैनं नानुशोचितुमर्हसि॥",
    hindiMeaning = "भगवान कहते हैं कि आत्मा अव्यक्त है – इन्द्रियों से जिसे देखा नहीं जा सकता। यह अचिन्त्य है – जिसका चिंतन भी मनुष्य के मन से परे है। यह अविकार है – इसमें कोई परिवर्तन नहीं होता। इन गुणों के कारण आत्मा सदा अचल और शाश्वत रहती है। जब आत्मा न दिखाई देती है, न समझ में आती है और न ही बदलती है, तो उसके लिए शोक करने का कोई कारण नहीं है। अर्जुन का शोक केवल देह तक सीमित है, आत्मा का उस पर कोई प्रभाव नहीं। इसलिए उसे शोक नहीं करना चाहिए।",
    englishMeaning = "The soul is said to be unmanifest, inconceivable, and immutable. Knowing this, one should not grieve over it."
    ),

    Shloka(
    number = 26,
    sanskrit = "अथ चैनं नित्यजातं नित्यं वा मन्यसे मृतम्। तथापि त्वं महाबाहो नैवं शोचितुमर्हसि॥ ",
    hindiMeaning = "कृष्ण कहते हैं कि यदि तू यह मान भी ले कि आत्मा बार-बार जन्म लेती है और मरती है, तब भी हे महाबाहो, तू शोक करने योग्य नहीं है। क्योंकि यदि आत्मा नित्य जन्म और मृत्यु को प्राप्त करती भी हो, तो यह एक स्वाभाविक चक्र है। जन्म के बाद मृत्यु और मृत्यु के बाद जन्म निश्चित है। इस चक्र पर शोक करना व्यर्थ है। विवेकशील व्यक्ति जानता है कि यह प्रकृति का नियम है। अर्जुन को यह शिक्षा दी जा रही है कि हर स्थिति में शोक अज्ञान का परिणाम है।",
    englishMeaning = "Even if you think the soul is constantly born and constantly dies, still, O mighty-armed, you should not grieve, for this is natural."
    ),

    Shloka(
    number = 27,
    sanskrit = "जातस्य हि ध्रुवो मृत्युर्ध्रुवं जन्म मृतस्य च। तस्मादपरिहार्येऽर्थे न त्वं शोचितुमर्हसि॥",
    hindiMeaning = "भगवान बताते हैं कि जिसने जन्म लिया है उसकी मृत्यु निश्चित है और जिसकी मृत्यु हुई है उसका जन्म भी निश्चित है। यह अपरिहार्य नियम है। इसलिए जिस बात को टाला नहीं जा सकता उसके लिए शोक करना व्यर्थ है। ज्ञानी इस सत्य को समझकर स्थिरचित्त रहते हैं। जीवन का यह चक्र निरंतर चलता है और इसका कोई अंत नहीं है। अर्जुन को यह समझना चाहिए कि मृत्यु पर शोक करना प्रकृति के नियमों की अवहेलना करना है।",
    englishMeaning = "For one who has taken birth, death is certain, and for one who dies, rebirth is also certain. Therefore, you should not grieve over the inevitable."
    ),

    Shloka(
    number = 28,
    sanskrit = "अव्यक्तादीनि भूतानि व्यक्तमध्यानि भारत। अव्यक्तनिधनान्येव तत्र का परिदेवना॥ ",
    hindiMeaning = "कृष्ण कहते हैं कि सभी प्राणी आरंभ में अव्यक्त रहते हैं, मध्य में व्यक्त होते हैं और अंत में पुनः अव्यक्त हो जाते हैं। यह जीवन का स्वाभाविक चक्र है। जब पहले और बाद में वे दिखाई नहीं देते, केवल बीच में दिखाई देते हैं, तो शोक का कारण कहाँ है? जन्म और मृत्यु केवल आत्मा के आवरण का परिवर्तन है। आत्मा स्वयं कभी प्रकट या अप्रकट नहीं होती, वह शाश्वत रहती है। अर्जुन को यह समझकर शोक छोड़ देना चाहिए।",
    englishMeaning = "Beings are unmanifest in their beginning, manifest in their middle, and unmanifest again in their end. Why, then, lament?"
    ),

    Shloka(
    number = 29,
    sanskrit = "आश्चर्यवत्पश्यति कश्चिदेनमाश्चर्यवद्वदति तथैव चान्यः। आश्चर्यवच्चैनमन्यः शृणोति श्रुत्वाऽप्येनं वेद न चैव कश्चित्॥",
    hindiMeaning = "आत्मा इतनी अद्भुत है कि कोई उसे देखकर आश्चर्यचकित होता है, कोई उसके बारे में बोलता है, कोई उसे सुनता है, और सुनने के बाद भी कोई-कोई ही वास्तव में उसे जान पाता है। यह आत्मा का रहस्य है कि वह मन और इन्द्रियों की सीमा से परे है। उसका ज्ञान केवल अनुभव से ही हो सकता है, मात्र शब्दों या सुनने से नहीं। इसलिए यह विषय आश्चर्य का बना रहता है। भगवान यह बताना चाहते हैं कि आत्मा की वास्तविकता दुर्लभ और गहन है। अर्जुन को यह समझना चाहिए कि आत्मा की महिमा शब्दों से परे है और इसके लिए अनुभव आवश्यक है।",
    englishMeaning = "Some see the soul as a wonder, some describe it as a wonder, and some hear of it as a wonder, yet even after hearing, none truly understands it."
    ),

    Shloka(
    number = 30,
    sanskrit = "देही नित्यमवध्योऽयं देहे सर्वस्य भारत। तस्मात्सर्वाणि भूतानि न त्वं शोचितुमर्हसि॥",
    hindiMeaning = "भगवान कहते हैं कि यह आत्मा जो शरीर में निवास करती है, वह सदा अवध्य और अविनाशी है। वह कभी नष्ट नहीं हो सकती। इसलिए, हे भरतवंशी, सभी प्राणियों के लिए शोक करना उचित नहीं है। शरीर नष्ट होता है लेकिन आत्मा अमर रहती है। अर्जुन को यह शिक्षा दी जा रही है कि आत्मा के अमरत्व को जानकर वह शोक से ऊपर उठे। यही ज्ञान उसे युद्ध के अपने कर्तव्य को निभाने में समर्थ करेगा।",
    englishMeaning = "The soul, dwelling in all bodies, is always indestructible. Therefore, O Bharata, you should not grieve for any living being."
    ),
    Shloka(
    number = 31,
    sanskrit = "स्वधर्ममपि चावेक्ष्य न विकम्पितुमर्हसि।\nधर्म्याद्धि युद्धाच्छ्रेयोऽन्यत्क्षत्रियस्य न विद्यते॥",
    hindiMeaning = "श्रीकृष्ण अर्जुन से कहते हैं कि तुम्हें अपने स्वधर्म की ओर भी देखना चाहिए। एक क्षत्रिय का परम कर्तव्य धर्म की रक्षा करना है, और उसके लिए आवश्यक होने पर युद्ध करना भी उसका धर्म है। यदि कोई क्षत्रिय धर्मयुद्ध से भागता है तो वह अपने सबसे बड़े कर्तव्य से विमुख होता है। युद्ध केवल लोभ या क्रोध से प्रेरित होकर नहीं किया जाता, बल्कि धर्म की रक्षा के लिए किया गया युद्ध ही श्रेष्ठ माना जाता है। अर्जुन, तुम्हारे सामने यह अवसर आया है कि तुम अधर्म के विरुद्ध खड़े होकर धर्म की रक्षा करो। ऐसे अवसर पर भय या मोह के कारण पीछे हटना तुम्हारे लिए कलंक और पतन का कारण बनेगा। अतः तुम्हें विचलित हुए बिना अपने धर्म का पालन करना चाहिए।",
    englishMeaning = "Krishna tells Arjuna that as a warrior, his duty is to fight for righteousness. For a Kshatriya, no duty is higher than participating in a just and righteous war. Therefore, he should not waver from his duty."
    ),

    Shloka(
    number = 32,
    sanskrit = "यदृच्छया चोपपन्नं स्वर्गद्वारमपावृतम्।\nसुखिनः क्षत्रियाः पार्थ लभन्ते युद्धमीदृशम्॥",
    hindiMeaning = "भगवान कहते हैं कि हे पार्थ! यह युद्ध तुम्हें संयोगवश प्राप्त हुआ है। यह ऐसा युद्ध है जो धर्म की स्थापना और अधर्म के नाश के लिए है। इसे करने से तुम्हारे लिए स्वर्ग के द्वार खुल जाते हैं। क्षत्रिय के लिए ऐसा धर्मयुद्ध जीवन का सबसे बड़ा सौभाग्य है। सामान्यतः लोग अपने जीवन में केवल सांसारिक कर्तव्यों में लगे रहते हैं, परंतु तुम्हें धर्म के लिए युद्ध करने का अवसर मिला है। यह अवसर बहुत दुर्लभ है और वही क्षत्रिय वास्तव में धन्य है जिसे ऐसा अवसर प्राप्त हो। इस प्रकार, तुम्हें इसे सौभाग्य मानकर स्वीकार करना चाहिए, न कि मोह और दुविधा में पड़कर त्याग करना चाहिए।",
    englishMeaning = "Krishna explains that a righteous war opens the gates of heaven for a warrior. Such opportunities are rare and bring great honor and spiritual benefit to a Kshatriya."
    ),

    Shloka(
    number = 33,
    sanskrit = "अथ चैत्त्वमिमं धर्म्यं संग्रामं न करिष्यसि।\nततः स्वधर्मं कीर्तिं च हित्वा पापमवाप्स्यसि॥",
    hindiMeaning = "यदि तुम इस धर्मयुद्ध को नहीं करोगे तो तुम अपने स्वधर्म का त्याग कर दोगे। अपने धर्म से विमुख होने पर तुम्हें पाप का भागी बनना पड़ेगा। एक क्षत्रिय के लिए धर्मयुद्ध से विमुख होना न केवल अधर्म है, बल्कि उसके जीवन का सबसे बड़ा कलंक भी है। इस त्याग से न तुम्हें यश मिलेगा और न आत्मिक शांति, बल्कि केवल पतन ही होगा। धर्म से विमुख होकर अर्जित जीवन कभी भी सुखदायी नहीं होता। संसार में सम्मान और स्वर्ग में स्थान, दोनों से तुम वंचित हो जाओगे। अतः धर्मयुद्ध से भागना तुम्हारे लिए केवल पाप और अपयश का कारण बनेगा।",
    englishMeaning = "If Arjuna refuses to fight this righteous war, he will abandon his duty and honor. By neglecting his responsibility, he will incur sin and face dishonor."
    ),

    Shloka(
    number = 34,
    sanskrit = "अकीर्तिं चापि भूतानि कथयिष्यन्ति तेऽव्ययाम्।\nसम्भावितस्य चाकीर्तिर्मरणादतिरिच्यते॥",
    hindiMeaning = "भगवान कहते हैं कि यदि तुम इस युद्ध से पीछे हटोगे तो लोग सदा तुम्हारी निंदा करेंगे। तुम्हारे वीरत्व और पराक्रम की जो प्रतिष्ठा है, वह लज्जा और कलंक में बदल जाएगी। संसार में जिनका सम्मान है, उनके लिए अपयश मृत्यु से भी अधिक दुःखद होता है। अर्जुन, तुम्हारा नाम वीरों में गिना जाता है, और यदि तुम मोह और भय के कारण युद्ध छोड़ दोगे तो लोग तुम्हें कायर कहेंगे। ऐसी बदनामी कभी समाप्त नहीं होगी और सदा तुम्हारा पीछा करेगी। इसलिए, तुम्हें यह समझना चाहिए कि अपयश सहना मृत्यु से भी अधिक पीड़ादायक है।",
    englishMeaning = "Krishna warns that if Arjuna abandons the battle, people will forever speak of his dishonor. For a respected warrior, dishonor is worse than death."
    ),

    Shloka(
    number = 35,
    sanskrit = "भयाद्रणादुपरतं मंस्यन्ते त्वां महारथाः।\nयेषां च त्वं बहुमतो भूत्वा यास्यसि लाघवम्॥",
    hindiMeaning = "हे अर्जुन! जिन महारथियों का तुम्हें अत्यधिक सम्मान प्राप्त है, वे भी यह सोचेंगे कि तुम युद्धभूमि से भय के कारण भाग गए। अभी तक वे तुम्हें महान योद्धा मानते थे, परंतु अब तुम्हारी दृष्टि में तुम्हारा महत्व घट जाएगा। यह न केवल तुम्हारे लिए कलंक होगा बल्कि तुम्हारी वीरता और प्रतिष्ठा को भी नष्ट कर देगा। सम्मानित व्यक्ति जब अपनी जिम्मेदारियों से भागता है, तब वह दूसरों की दृष्टि में भी छोटा हो जाता है। इस प्रकार, तुम्हारी प्रतिष्ठा और मान-सम्मान दोनों समाप्त हो जाएंगे। इसलिए तुम्हें यह सोचकर भी युद्ध से पीछे नहीं हटना चाहिए।",
    englishMeaning = "The great warriors will think Arjuna fled out of fear. Those who once respected him will now see him as weak, causing a loss of honor and dignity."
    ),

    Shloka(
    number = 36,
    sanskrit = "अवाच्यवादांश्च बहून्वदिष्यन्ति तवाहिताः।\nनिन्दन्तस्तव सामर्थ्यं ततो दुःखतरं नु किम्॥",
    hindiMeaning = "भगवान आगे कहते हैं कि तुम्हारे शत्रु भी तुम्हारे बारे में अपशब्द कहेंगे। वे तुम्हारी वीरता और सामर्थ्य का उपहास उड़ाएंगे। तुम्हें अपमानित करने के लिए वे अनेक प्रकार की निंदाएँ करेंगे। सोचो, तुम्हारे लिए इससे बड़ा दुःख और क्या हो सकता है? संसार में अपमान सहना एक वीर के लिए सबसे बड़ी पीड़ा है। यश और सम्मान की रक्षा करना हर योद्धा का धर्म है। यदि तुम अपने ही शत्रुओं से उपहास का पात्र बनोगे तो तुम्हारा जीवन निरर्थक हो जाएगा। इसलिए, हे अर्जुन! युद्ध से विमुख होना किसी भी प्रकार तुम्हारे लिए उचित नहीं है।",
    englishMeaning = "Enemies will insult Arjuna and speak harsh words, mocking his strength. Krishna emphasizes that such humiliation would be more painful than death itself."
    ),

    Shloka(
    number = 37,
    sanskrit = "हतो वा प्राप्स्यसि स्वर्गं जित्वा वा भोक्ष्यसे महीम्।\nतस्मादुत्तिष्ठ कौन्तेय युद्धाय कृतनिश्चयः॥",
    hindiMeaning = "हे कौन्तेय! यदि युद्ध में तुम मारे जाते हो तो स्वर्ग को प्राप्त करोगे, और यदि विजयी होते हो तो पृथ्वी पर राजसुख भोगोगे। दोनों ही स्थितियों में तुम्हारा कल्याण है। इसलिए अब किसी भी प्रकार की शंका या मोह मत करो। अपने कर्तव्य को समझो और दृढ़ निश्चय के साथ युद्ध के लिए उठो। यह युद्ध केवल सांसारिक लाभ के लिए नहीं, बल्कि धर्म की रक्षा के लिए है। जो भी परिणाम होगा, वह तुम्हारे लिए मंगलकारी ही होगा। अतः तुम्हें पूरी दृढ़ता और निश्चय के साथ युद्ध करना चाहिए।",
    englishMeaning = "If killed, Arjuna will attain heaven; if victorious, he will enjoy ruling the earth. Therefore, Krishna urges him to rise with determination and fight."
    ),

    Shloka(
    number = 38,
    sanskrit = "सुखदुःखे समे कृत्वा लाभालाभौ जयाजयौ।\nततो युद्धाय युज्यस्व नैवं पापमवाप्स्यसि॥",
    hindiMeaning = "श्रीकृष्ण कहते हैं कि सुख-दुःख, लाभ-हानि और जय-पराजय में समभाव रखो। जब मनुष्य इन द्वंद्वों से ऊपर उठकर अपने कर्तव्य का पालन करता है, तब वह कर्म से बंधा नहीं रहता। धर्मयुद्ध करते समय तुम्हें किसी भी प्रकार का मोह या स्वार्थ नहीं होना चाहिए। यदि तुम्हारा मन इन सब से मुक्त होगा तो तुम्हें पाप का स्पर्श भी नहीं होगा। युद्ध का परिणाम चाहे जैसा भी हो, यदि वह धर्म और कर्तव्य के अनुसार है तो वह शुद्ध कर्म है। इस प्रकार, निष्काम भाव से युद्ध करो और पाप से बचो।",
    englishMeaning = "Krishna advises Arjuna to treat pleasure and pain, gain and loss, victory and defeat equally. Fighting with such balance will free him from sin."
    ),

    Shloka(
    number = 39,
    sanskrit = "एषा तेऽभिहिता सांख्ये बुद्धिर्योगे त्विमां शृणु।\nबुद्ध्या युक्तो यया पार्थ कर्मबन्धं प्रहास्यसि॥",
    hindiMeaning = "भगवान कहते हैं कि अब तक मैंने तुम्हें सांख्य की दृष्टि से यह ज्ञान बताया है। अब योग की बुद्धि को सुनो, जिसके द्वारा तुम कर्मबंधन से मुक्त हो सकते हो। जब मनुष्य विवेकपूर्ण बुद्धि से अपने कर्तव्य को करता है और उसके परिणाम से आसक्त नहीं होता, तब वह कर्म के बंधन से मुक्त हो जाता है। यह बुद्धि योग केवल सांसारिक सफलता के लिए नहीं, बल्कि आत्मिक मुक्ति के लिए भी आवश्यक है। अर्जुन! यदि तुम इस बुद्धि से युक्त होकर कर्म करोगे तो तुम्हें किसी प्रकार का बंधन नहीं होगा। यही वह मार्ग है जो मोक्ष की ओर ले जाता है।",
    englishMeaning = "Krishna explains that he has taught Arjuna knowledge from the Sankhya perspective. Now, he introduces the wisdom of Yoga, which helps one act without being bound by karma."
    ),

    Shloka(
    number = 40,
    sanskrit = "नेहाभिक्रमनाशोऽस्ति प्रत्यवायो न विद्यते।\nस्वल्पमप्यस्य धर्मस्य त्रायते महतो भयात्॥",
    hindiMeaning = "भगवान कहते हैं कि इस योग में कभी भी प्रयत्न व्यर्थ नहीं जाता। इसमें किसी प्रकार का विपरीत परिणाम नहीं होता। थोड़ा सा भी योग साधन मनुष्य को महान भय से बचा लेता है। संसार में हर कर्म का कोई न कोई परिणाम अवश्य होता है, परंतु योगयुक्त कर्म कभी व्यर्थ नहीं होता। यह मनुष्य को जन्म-मृत्यु के भय से मुक्त करता है और मुक्ति की ओर ले जाता है। इस मार्ग में छोटी-सी साधना भी अमूल्य है। अतः हे अर्जुन! यदि तुम इस योग का थोड़ा भी अभ्यास करोगे तो यह तुम्हारे लिए महान कल्याणकारी होगा।",
    englishMeaning = "In this path of Yoga, no effort is ever wasted, and no harm comes from it. Even a small practice of this discipline saves one from great fear and leads toward liberation."
    ),

    Shloka(
    number = 41,
    sanskrit = "व्यवसायात्मिका बुद्धिरेकेह कुरुनन्दन।\nबहुशाखा ह्यनन्ताश्च बुद्धयोऽव्यवसायिनाम्॥",
    hindiMeaning = "भगवान कहते हैं कि हे कुरुनन्दन! इस मार्ग में केवल एक ही दृढ़ निश्चययुक्त बुद्धि आवश्यक है। जब मनुष्य अपने लक्ष्य को स्पष्ट रूप से पहचान लेता है, तो उसकी सारी प्रवृत्तियाँ उसी लक्ष्य की ओर केंद्रित हो जाती हैं। परंतु जिनकी बुद्धि स्थिर नहीं होती, उनकी इच्छाएँ अनंत शाखाओं में बँटी रहती हैं। वे कभी एक दिशा में तो कभी दूसरी दिशा में भटकते रहते हैं। ऐसे लोग कभी भी अपने जीवन में शांति या स्थिरता प्राप्त नहीं कर सकते। दृढ़ निश्चय और एकाग्रता ही आध्यात्मिक उन्नति की कुंजी है। इसलिए अर्जुन! तुम्हें अपनी बुद्धि को एक ही लक्ष्य पर स्थिर करना चाहिए, और वह है आत्मज्ञान और मुक्ति।",
    englishMeaning = "Krishna explains that a resolute and focused mind is one-pointed. Those without determination have endless, scattered thoughts, leading them away from the true path."
    ),

    Shloka(
    number = 42,
    sanskrit = "यामिमां पुष्पितां वाचं प्रवदन्त्यविपश्चितः।\nवेदवादरताः पार्थ नान्यदस्तीति वादिनः॥",
    hindiMeaning = "यहाँ भगवान कहते हैं कि अविवेकी लोग वेदों के उन भागों में आसक्त रहते हैं जो केवल कर्मकांड और स्वर्ग प्राप्ति की बातें करते हैं। वे लोग पुष्पित वाणी बोलते हैं, अर्थात् ऐसे मधुर शब्द जिनमें भोग और स्वर्ग के सुखों का वर्णन हो। वे यह मानते हैं कि इन कर्मकांडों के अतिरिक्त कोई और श्रेष्ठ मार्ग नहीं है। इस प्रकार उनका ध्यान केवल बाहरी आडंबरों और अस्थायी सुखों तक सीमित रह जाता है। वे आत्मज्ञान के गहरे रहस्य को नहीं समझ पाते। उनके लिए धर्म केवल यज्ञ, दान और स्वर्ग तक सीमित है। लेकिन सच्चा साधक इन सीमाओं को पार कर आत्मा की शांति और परम सत्य की ओर बढ़ता है।",
    englishMeaning = "Krishna says that the unwise delight in flowery words of the Vedas, focusing only on rituals and promises of heavenly pleasures. They believe nothing higher exists beyond such rituals."
    ),

    Shloka(
    number = 43,
    sanskrit = "कामात्मानः स्वर्गपरा जन्मकर्मफलप्रदाम्।\nक्रियाविशेषबहुलां भोगैश्वर्यगतिं प्रति॥",
    hindiMeaning = "श्रीकृष्ण बताते हैं कि ऐसे लोग कामनाओं से प्रेरित होकर केवल स्वर्ग प्राप्ति की आकांक्षा रखते हैं। उनका मन जन्म और कर्म के फल में बँधा रहता है। वे विशेष-विशेष कर्मकांड करते हैं, जिनसे उन्हें भोग और ऐश्वर्य प्राप्त हो सके। उनका ध्यान केवल सुख-सुविधाओं और ऐश्वर्य के मार्ग पर केंद्रित रहता है। परंतु यह सब अस्थायी है और आत्मा को शांति नहीं देता। मनुष्य जब तक इन इच्छाओं और भोग की वासनाओं में बँधा रहेगा, तब तक वह आत्मज्ञान को प्राप्त नहीं कर सकता। इसलिए अर्जुन, तुम्हें समझना चाहिए कि सच्चा पथ इन अस्थायी लाभों से ऊपर उठकर आत्मा की मुक्ति की ओर जाता है।",
    englishMeaning = "Those who are driven by desires cling to heavenly rewards and rituals. Their focus is on enjoyment and power, not on spiritual liberation."
    ),

    Shloka(
    number = 44,
    sanskrit = "भोगैश्वर्यप्रसक्तानां तयापहृतचेतसाम्।\nव्यवसायात्मिका बुद्धिः समाधौ न विधीयते॥",
    hindiMeaning = "भगवान कहते हैं कि जिन लोगों का मन भोग और ऐश्वर्य में फँसा हुआ है, उनका चित्त स्थिर नहीं हो सकता। उनकी बुद्धि कामनाओं से ढँक जाती है और वे एकाग्र नहीं हो पाते। समाधि का अर्थ है आत्मा में स्थित होना, परंतु जिनकी बुद्धि निरंतर भोग की ओर दौड़ती रहती है, वे आत्मा की शांति का अनुभव नहीं कर पाते। ऐसे लोग जीवन भर बाहरी सुख-सुविधाओं के पीछे भागते रहते हैं। उनके लिए आत्मज्ञान और मुक्ति का मार्ग कठिन हो जाता है। इसलिए, अर्जुन! यह आवश्यक है कि तुम भोग और ऐश्वर्य की आसक्ति से मुक्त होकर अपनी बुद्धि को स्थिर करो। तभी सच्चा योग संभव होगा।",
    englishMeaning = "Those attached to pleasure and wealth lose their ability to focus on truth. A mind distracted by desires cannot achieve steadiness or union with the Self."
    ),

    Shloka(
    number = 45,
    sanskrit = "त्रैगुण्यविषया वेदा निस्त्रैगुण्यो भवार्जुन।\nनिर्द्वन्द्वो नित्यसत्त्वस्थो निर्योगक्षेम आत्मवान्॥",
    hindiMeaning = "श्रीकृष्ण अर्जुन से कहते हैं कि वेद मुख्यतः तीन गुणों – सत्त्व, रज और तम – से संबंधित विषयों का वर्णन करते हैं। लेकिन हे अर्जुन! तुम्हें इन गुणों से ऊपर उठना चाहिए। द्वंद्वों से मुक्त होकर समभाव में स्थित रहो। नित्य सत्त्व में स्थिर रहकर योग और क्षेम (सुख की प्राप्ति और उसकी रक्षा) की चिंता छोड़ दो। आत्मा में स्थित रहकर अपने जीवन का संचालन करो। जब मनुष्य द्वंद्वों – जैसे सुख-दुःख, लाभ-हानि, जय-पराजय – से ऊपर उठ जाता है, तभी वह परम शांति को प्राप्त कर सकता है। यह स्थिति केवल आत्मबोध और आत्मनिष्ठा से प्राप्त होती है।",
    englishMeaning = "The Vedas deal with the three modes of nature. Krishna advises Arjuna to rise above them, be free from dualities, remain steadfast in purity, and focus on the Self rather than material gain."
    ),

    Shloka(
    number = 46,
    sanskrit = "यावानर्थ उदपाने सर्वतः सम्प्लुतोदके।\nतावान्सर्वेषु वेदेषु ब्राह्मणस्य विजानतः॥",
    hindiMeaning = "भगवान उदाहरण देते हैं कि जैसे एक छोटे कुएँ की उपयोगिता उस समय समाप्त हो जाती है जब चारों ओर जल से भरा हुआ सरोवर उपलब्ध हो, वैसे ही आत्मा को जानने वाले के लिए वेदों के कर्मकांडों की उपयोगिता समाप्त हो जाती है। आत्मज्ञानी मनुष्य वेदों की गहराई और उनके वास्तविक उद्देश्य को समझ लेता है। उसके लिए केवल बाहरी अनुष्ठान और यज्ञ आवश्यक नहीं रहते। वह जान लेता है कि परम सत्य आत्मा में ही निहित है। इसलिए, जो आत्मज्ञानी होता है, उसके लिए वेदों के कर्मकांड उसी प्रकार गौण हो जाते हैं जैसे सरोवर के सामने कुएँ की आवश्यकता नहीं रहती।",
    englishMeaning = "Just as a reservoir of water serves all purposes of a well, for the enlightened person, the entire purpose of the Vedas is fulfilled. Rituals become secondary once the truth is realized."
    ),

    Shloka(
    number = 47,
    sanskrit = "कर्मण्येवाधिकारस्ते मा फलेषु कदाचन।\nमा कर्मफलहेतुर्भूर्मा ते संगोऽस्त्वकर्मणि॥",
    hindiMeaning = "यह गीता का अत्यंत प्रसिद्ध श्लोक है। भगवान अर्जुन से कहते हैं कि तुम्हारा अधिकार केवल कर्म करने में है, उसके फल में नहीं। तुम कर्म के फल के कारण मत बनो और न ही अकर्मण्यता की ओर झुको। मनुष्य को अपने कर्तव्य का पालन करना चाहिए, चाहे परिणाम जैसा भी हो। जब कोई व्यक्ति फल की चिंता छोड़ देता है, तभी उसका कर्म निष्काम और शुद्ध हो जाता है। कर्म से भागना भी उचित नहीं है, क्योंकि जीवन में सक्रियता आवश्यक है। इसलिए, अर्जुन! अपने धर्म का पालन करो और फल की चिंता ईश्वर पर छोड़ दो।",
    englishMeaning = "You have the right to perform your duty, but not to the results. Do not be attached to the fruits of action, and do not fall into inaction."
    ),

    Shloka(
    number = 48,
    sanskrit = "योगस्थः कुरु कर्माणि सङ्गं त्यक्त्वा धनञ्जय।\nसिद्ध्यसिद्ध्योः समो भूत्वा समत्वं योग उच्यते॥",
    hindiMeaning = "भगवान कहते हैं कि हे धनंजय! योग में स्थित होकर अपने कर्म करो। आसक्ति छोड़कर कर्म करने का नाम ही योग है। सफलता और असफलता दोनों में समान भाव रखो। यही समत्व ही वास्तविक योग कहलाता है। जब मनुष्य कर्म के परिणाम को लेकर चिंतित नहीं होता, तब वह अपने कर्म को पूर्ण समर्पण और शांति से करता है। ऐसा योगी कभी निराश या अहंकारी नहीं होता। वह हमेशा समभाव में स्थित रहता है। यही स्थिति आत्मिक उन्नति और मोक्ष की ओर ले जाती है।",
    englishMeaning = "Perform your duty with detachment, O Arjuna. Treat success and failure alike, for true yoga is balance and equanimity."
    ),

    Shloka(
    number = 49,
    sanskrit = "दूरेण ह्यवरं कर्म बुद्धियोगाद्धनञ्जय।\nबुद्धौ शरणमन्विच्छ कृपणाः फलहेतवः॥",
    hindiMeaning = "श्रीकृष्ण कहते हैं कि हे धनंजय! केवल फल की कामना से किया गया कर्म, बुद्धियोग से किया गया कर्म की तुलना में बहुत ही निम्न है। बुद्धियोग अर्थात् विवेक और निष्काम भाव से कर्म करना। इसलिए तुम बुद्धियोग की शरण लो। जो लोग केवल कर्मफल के लोभी होते हैं, वे दयनीय हैं। वे न तो आत्मिक शांति पाते हैं और न ही सच्चे सुख का अनुभव करते हैं। कर्म का उद्देश्य केवल सांसारिक लाभ नहीं होना चाहिए, बल्कि आत्मा की उन्नति होना चाहिए। इसीलिए अर्जुन, तुम विवेकयुक्त कर्म का ही आश्रय लो।",
    englishMeaning = "Krishna tells Arjuna that action done with selfish desire is far inferior to action performed with wisdom. Seek refuge in wisdom, for those motivated only by results are pitiable."
    ),

    Shloka(
    number = 50,
    sanskrit = "बुद्धियुक्तो जहातीह उभे सुकृतदुष्कृते।\nतस्माद्योगाय युज्यस्व योगः कर्मसु कौशलम्॥",
    hindiMeaning = "भगवान कहते हैं कि जो व्यक्ति बुद्धियोग से युक्त होता है, वह इस संसार में पुण्य और पाप दोनों से ऊपर उठ जाता है। उसका कर्म न तो उसे बांधता है और न ही उसे पतन की ओर ले जाता है। इसलिए हे अर्जुन! तुम्हें योग में स्थित होकर अपने कर्म करने चाहिए। योग ही कर्म में कौशल है, क्योंकि यह मनुष्य को निष्काम भाव से कर्म करने की प्रेरणा देता है। ऐसा योगी कर्म के परिणाम से बंधा नहीं रहता और शांति में स्थित होता है। इस प्रकार, कर्मयोगी ही सच्चे अर्थों में स्वतंत्र और मुक्त होता है।",
    englishMeaning = "One who acts with wisdom transcends both good and bad results. Therefore, Krishna says, practice yoga, for yoga is skill in action."
    ),
    Shloka(
    number = 51,
    sanskrit = "कर्मजं बुद्धियुक्ता हि फलं त्यक्त्वा मनीषिणः।\nजन्मबन्धविनिर्मुक्ताः पदं गच्छन्त्यनामयम्॥",
    hindiMeaning = "भगवान कहते हैं कि बुद्धियोग से युक्त ज्ञानीजन अपने कर्मों के फलों को त्याग देते हैं। वे फल की आसक्ति से मुक्त होकर केवल कर्तव्य भाव से कर्म करते हैं। ऐसे व्यक्ति जन्म और कर्म के बंधनों से मुक्त हो जाते हैं। जब मनुष्य फल की इच्छा छोड़ देता है, तभी उसके कर्म पवित्र और मुक्तिदायक बनते हैं। बुद्धिमान व्यक्ति यह समझता है कि फल अस्थायी है, परंतु आत्मा शाश्वत है। इसलिए वह आत्मा की शांति के लिए ही कर्म करता है। ऐसे साधक अंततः उस पद को प्राप्त करते हैं जहाँ कोई दुख, रोग या मोह नहीं होता।",
    englishMeaning = "The wise, acting with balanced intellect, renounce the fruits of their actions. They become free from the bondage of rebirth and reach a state of peace beyond suffering."
    ),

    Shloka(
    number = 52,
    sanskrit = "यदा ते मोहकलिलं बुद्धिर्व्यतितरिष्यति।\nतदा गन्तासि निर्वेदं श्रोतव्यस्य श्रुतस्य च॥",
    hindiMeaning = "श्रीकृष्ण कहते हैं कि जब तुम्हारी बुद्धि मोह के घने जंगल को पार कर जाएगी, तब तुम सुनने योग्य और सुने हुए सभी शास्त्रों के प्रति उदासीन हो जाओगे। इसका अर्थ यह है कि जब आत्मज्ञान प्राप्त होता है तो शास्त्रों में वर्णित कर्मकांडों और उपदेशों की आवश्यकता कम हो जाती है। क्योंकि साधक स्वयं सत्य का अनुभव कर लेता है। शास्त्र केवल मार्ग दिखाते हैं, परंतु आत्मज्ञान ही वास्तविक गंतव्य है। मोह से मुक्त होकर बुद्धि स्थिर और निर्मल हो जाती है। ऐसी अवस्था में व्यक्ति बाहरी ज्ञान के बजाय आंतरिक अनुभूति पर आश्रित होता है।",
    englishMeaning = "When your intellect rises beyond delusion, you will lose interest in what is yet to be heard and what has already been heard. Direct realization will take precedence over scriptures."
    ),

    Shloka(
    number = 53,
    sanskrit = "श्रुतिविप्रतिपन्ना ते यदा स्थास्यति निश्चला।\nसमाधावचला बुद्धिस्तदा योगमवाप्स्यसि॥",
    hindiMeaning = "भगवान कहते हैं कि जब तुम्हारी बुद्धि शास्त्रों के भिन्न-भिन्न मतों से विचलित नहीं होगी और स्थिर होकर आत्मा में एकाग्र हो जाएगी, तब तुम योग को प्राप्त करोगे। यह वह स्थिति है जब साधक बाहरी बहस और मतभेदों से ऊपर उठकर आत्मा की शांति में स्थित होता है। उसकी बुद्धि अब इधर-उधर नहीं दौड़ती, बल्कि केवल परम सत्य पर टिकी रहती है। यही वास्तविक समाधि की स्थिति है। इस अवस्था में साधक सच्चे योगी के रूप में जाना जाता है। और यही उसे मुक्ति के मार्ग पर स्थिर करता है।",
    englishMeaning = "When your mind is unmoved by conflicting teachings and remains steady in the Self, you will truly attain yoga. This is the state of unshaken concentration."
    ),

    Shloka(
    number = 54,
    sanskrit = "अर्जुन उवाच — स्थितप्रज्ञस्य का भाषा समाधिस्थस्य केशव।\nस्थितधीः किं प्रभाषेत किमासीत व्रजेत किम्॥",
    hindiMeaning = "अर्जुन भगवान से प्रश्न करते हैं: हे केशव! जो व्यक्ति समाधि में स्थित होकर स्थितप्रज्ञ कहलाता है, उसकी पहचान क्या है? वह किस प्रकार बोलता है, कैसे बैठता है और कैसे चलता है? अर्जुन यह जानना चाहता है कि स्थितप्रज्ञ व्यक्ति के व्यवहार और जीवन की विशेषताएँ क्या होती हैं। वह यह समझना चाहता है कि आत्मज्ञानी व्यक्ति की बाहरी दुनिया में अभिव्यक्ति कैसी होती है। क्योंकि आत्मिक उन्नति का वास्तविक प्रमाण उसके आचरण और जीवनशैली में ही दिखाई देता है। यह प्रश्न गीता के आगे के उपदेश का आधार बनता है।",
    englishMeaning = "Arjuna asks Krishna about the qualities of a person of steady wisdom, established in meditation. He wants to know how such a person speaks, sits, and walks."
    ),

    Shloka(
    number = 55,
    sanskrit = "श्रीभगवानुवाच — प्रजहाति यदा कामान्सर्वान्पार्थ मनोगतान्।\nआत्मन्येवात्मना तुष्टः स्थितप्रज्ञस्तदोच्यते॥",
    hindiMeaning = "भगवान उत्तर देते हैं कि हे पार्थ! जब व्यक्ति अपने मन में उत्पन्न सभी कामनाओं को त्याग देता है और आत्मा में ही आत्मा द्वारा संतुष्ट होता है, तब उसे स्थितप्रज्ञ कहा जाता है। इसका अर्थ है कि वह बाहरी भोग और इच्छाओं में सुख नहीं खोजता। उसका सुख केवल आत्मा की शांति और ज्ञान में होता है। जब मनुष्य आत्मा में संतुष्ट हो जाता है, तब उसके लिए संसार की कोई वस्तु आकर्षक नहीं रहती। यह स्थिति वैराग्य और आत्मसंतोष की पराकाष्ठा है। ऐसा व्यक्ति वास्तव में स्थितप्रज्ञ कहलाता है।",
    englishMeaning = "Krishna explains that one who gives up all desires of the mind and is satisfied within the Self alone is called a person of steady wisdom."
    ),

    Shloka(
    number = 56,
    sanskrit = "दुःखेष्वनुद्विग्नमना: सुखेषु विगतस्पृहः।\nवीतरागभयक्रोधः स्थितधीर्मुनिरुच्यते॥",
    hindiMeaning = "भगवान कहते हैं कि जो व्यक्ति दुःख में विचलित नहीं होता और सुख में भी आसक्ति नहीं रखता, वही सच्चा मुनि और स्थितधी होता है। वह राग, भय और क्रोध से मुक्त हो जाता है। उसकी बुद्धि सदा संतुलित रहती है। दुःख आने पर वह व्याकुल नहीं होता और सुख मिलने पर अहंकार या लालच में नहीं पड़ता। वह संसार के द्वंद्वों से परे होकर आत्मा में स्थित रहता है। यह स्थिति तभी संभव है जब मनुष्य अपने भीतर वैराग्य और आत्मसंयम विकसित करे।",
    englishMeaning = "A sage of steady mind is undisturbed by sorrow, free from craving in happiness, and free from attachment, fear, and anger. Such balance marks true wisdom."
    ),

    Shloka(
    number = 57,
    sanskrit = "यः सर्वत्रानभिस्नेहस्तत्तत्प्राप्य शुभाशुभम्।\nनाभिनन्दति न द्वेष्टि तस्य प्रज्ञा प्रतिष्ठिता॥",
    hindiMeaning = "श्रीकृष्ण कहते हैं कि जो व्यक्ति किसी भी वस्तु या व्यक्ति से आसक्ति नहीं रखता, वही सच्चा स्थितप्रज्ञ है। जब उसे शुभ या अशुभ परिस्थितियाँ मिलती हैं तो वह न तो प्रसन्न होकर उछलता है और न ही दुःखी होकर गिरता है। उसका मन हमेशा समभाव में रहता है। यह समभाव उसे शांति और स्थिरता प्रदान करता है। वह जानता है कि जीवन की सभी परिस्थितियाँ अस्थायी हैं। इसलिए वह उनमें फँसकर अपना संतुलन नहीं खोता।",
    englishMeaning = "One whose mind is unattached, who does not rejoice in good fortune or hate misfortune, is firmly established in wisdom. Such detachment brings peace."
    ),

    Shloka(
    number = 58,
    sanskrit = "यदा संहरते चायं कूर्मोऽङ्गानीव सर्वशः।\nइन्द्रियाणीन्द्रियार्थेभ्यस्तस्य प्रज्ञा प्रतिष्ठिता॥",
    hindiMeaning = "भगवान कहते हैं कि जैसे कछुआ अपने अंगों को भीतर समेट लेता है, वैसे ही जब साधक अपने इन्द्रियों को विषयों से हटा लेता है, तब उसकी प्रज्ञा स्थिर हो जाती है। इसका अर्थ यह है कि आत्मज्ञानी व्यक्ति अपनी इन्द्रियों पर नियंत्रण रखता है। वह बाहरी आकर्षणों से प्रभावित नहीं होता। उसकी इन्द्रियाँ केवल आवश्यक कार्य में लगती हैं, अन्यथा वे आत्मा में ही लीन रहती हैं। यह संयम ही उसे स्थिरता और शांति प्रदान करता है।",
    englishMeaning = "Like a tortoise withdrawing its limbs, one who withdraws the senses from sense-objects is firmly established in wisdom. Self-control leads to steadiness."
    ),

    Shloka(
    number = 59,
    sanskrit = "विषया विनिवर्तन्ते निराहारस्य देहिनः।\nरसवर्जं रसोऽप्यस्य परं दृष्ट्वा निवर्तते॥",
    hindiMeaning = "भगवान कहते हैं कि विषय भोग से दूर रहने पर भी मनुष्य के भीतर उनकी इच्छा बनी रहती है। परंतु जब वह परम सत्य का दर्शन करता है, तब उसकी आसक्ति स्वतः समाप्त हो जाती है। केवल बाहरी संयम से इच्छाएँ नहीं मिटतीं, बल्कि आत्मज्ञान से ही वे नष्ट होती हैं। जब मनुष्य आत्मा की शांति और परम आनंद का अनुभव करता है, तब उसे संसार के भोग फीके लगने लगते हैं। यह स्थिति साधक को पूर्ण वैराग्य की ओर ले जाती है।",
    englishMeaning = "Objects of desire may leave a person who restrains himself, but the taste for them remains. Only upon realizing the Supreme does even this taste vanish."
    ),

    Shloka(
    number = 60,
    sanskrit = "यततो ह्यपि कौन्तेय पुरुषस्य विपश्चितः।\nइन्द्रियाणि प्रमाथीनि हरन्ति प्रसभं मनः॥",
    hindiMeaning = "भगवान कहते हैं कि हे कौन्तेय! जब कोई विवेकी व्यक्ति प्रयास करता है तब भी इन्द्रियाँ बलपूर्वक उसके मन को विचलित कर सकती हैं। इन्द्रियाँ अत्यंत चंचल और बलवान हैं। यदि साधक सावधान न रहे तो वे उसे मार्ग से भटका सकती हैं। इसलिए आत्मसंयम और साधना निरंतर आवश्यक है। केवल ज्ञान प्राप्त कर लेना पर्याप्त नहीं है, बल्कि इन्द्रियों पर नियंत्रण बनाए रखना ही सच्चे योग का अंग है।",
    englishMeaning = "Even for the wise and striving person, the restless senses can carry away the mind. Hence vigilance and self-control are essential on the spiritual path."
    ),
    Shloka(
    number = 61,
    sanskrit = "तानि सर्वाणि संयम्य युक्त आसीत मत्परः।\nवशे हि यस्येन्द्रियाणि तस्य प्रज्ञा प्रतिष्ठिता॥",
    hindiMeaning = "भगवान कहते हैं कि जो साधक अपनी सभी इन्द्रियों को वश में रखकर मेरे परायण होकर बैठता है, वही वास्तव में स्थिर बुद्धि वाला है। आत्मसंयम के बिना ज्ञान टिक नहीं सकता। जब तक इन्द्रियाँ विषयों में भटकती हैं, तब तक मनुष्य का ध्यान भगवान में स्थिर नहीं हो सकता। लेकिन जो व्यक्ति इन्द्रियों को नियंत्रण में रखकर उनका प्रयोग केवल आवश्यक कार्यों में करता है, उसकी बुद्धि परमात्मा में स्थिर हो जाती है। ऐसे साधक का मन कभी डगमगाता नहीं है। उसकी चेतना परम तत्व में स्थिर होकर शांति प्राप्त करती है।",
    englishMeaning = "One who controls all the senses and remains devoted to Me is steadfast in wisdom. Self-control and devotion make the mind firm and steady."
    ),

    Shloka(
    number = 62,
    sanskrit = "ध्यायतो विषयान्पुंसः सङ्गस्तेषूपजायते।\nसङ्गात्सञ्जायते कामः कामात्क्रोधोऽभिजायते॥",
    hindiMeaning = "श्रीकृष्ण चेतावनी देते हैं कि जब मनुष्य विषयों का लगातार चिंतन करता है, तो उनमें आसक्ति उत्पन्न होती है। आसक्ति से इच्छा जन्म लेती है और इच्छा पूरी न होने पर क्रोध उत्पन्न होता है। यही क्रोध आगे मनुष्य की बुद्धि को नष्ट कर देता है। इस प्रकार विषयों का चिंतन ही बंधन और पतन का कारण बनता है। साधक को चाहिए कि वह मन को बार-बार विषयों में न ले जाकर आत्मा और भगवान में लगाए। तभी वह स्थिर रह सकता है।",
    englishMeaning = "When one constantly thinks of sense objects, attachment develops. From attachment comes desire, and from desire arises anger when desires are not fulfilled."
    ),

    Shloka(
    number = 63,
    sanskrit = "क्रोधाद्भवति संमोहः संमोहात्स्मृतिविभ्रमः।\nस्मृतिभ्रंशाद् बुद्धिनाशो बुद्धिनाशात्प्रणश्यति॥",
    hindiMeaning = "भगवान कहते हैं कि क्रोध से मोह उत्पन्न होता है, मोह से स्मृति का भ्रम होता है। जब स्मृति नष्ट होती है, तब बुद्धि का नाश हो जाता है। और जब बुद्धि नष्ट होती है, तब मनुष्य का पतन निश्चित हो जाता है। यह पतन ही उसके जीवन को विनाश की ओर ले जाता है। इसलिए साधक को चाहिए कि वह कामना और क्रोध को आरंभ में ही रोक दे। जो व्यक्ति विवेक और धैर्य से चलता है, वह इस श्रृंखला में फँसने से बच जाता है।",
    englishMeaning = "From anger arises delusion, from delusion loss of memory, from loss of memory destruction of intellect, and with destroyed intellect, one is ruined."
    ),

    Shloka(
    number = 64,
    sanskrit = "रागद्वेषवियुक्तैस्तु विषयानिन्द्रियैश्चरन्।\nआत्मवश्यैर्विधेयात्मा प्रसादमधिगच्छति॥",
    hindiMeaning = "श्रीकृष्ण बताते हैं कि जब साधक आसक्ति और द्वेष से मुक्त होकर इन्द्रियों से विषयों का उपयोग करता है, तब उसका मन शुद्ध और शांत हो जाता है। इन्द्रियों का दमन नहीं, बल्कि उनका संयम आवश्यक है। जब मनुष्य अपने मन को वश में करके समभाव से व्यवहार करता है, तो उसके भीतर प्रसन्नता और संतोष की अनुभूति होती है। यह संतोष ही आत्मा की शांति और संतुलन का आधार है। ऐसे व्यक्ति को किसी प्रकार की असंतुलन या दुःख नहीं सताता।",
    englishMeaning = "One who moves among objects free from attachment and aversion, with self-control, attains peace of mind. Balance leads to inner harmony."
    ),

    Shloka(
    number = 65,
    sanskrit = "प्रसादे सर्वदुःखानां हानिरस्योपजायते।\nप्रसन्नचेतसो ह्याशु बुद्धिः पर्यवतिष्ठते॥",
    hindiMeaning = "भगवान कहते हैं कि जब मनुष्य का मन प्रसन्न और शांत होता है, तब उसके सभी दुःख नष्ट हो जाते हैं। शांत मन में बुद्धि तुरंत स्थिर हो जाती है। अशांत मन कभी निर्णय नहीं ले सकता, परंतु शांत और प्रसन्नचित्त व्यक्ति का विवेक सदा जाग्रत रहता है। यह प्रसन्नता बाहरी वस्तुओं से नहीं, बल्कि भीतर की आत्मिक शांति से आती है। यही आत्मशांति सभी बंधनों को काट देती है और साधक को स्थिर बनाती है।",
    englishMeaning = "In peace of mind, all sorrows end. For the calm and cheerful person, intellect becomes steady and clear."
    ),

    Shloka(
    number = 66,
    sanskrit = "नास्ति बुद्धिरयुक्तस्य न चायुक्तस्य भावना।\nन चाभावयतः शान्तिरशान्तस्य कुतः सुखम्॥",
    hindiMeaning = "श्रीकृष्ण कहते हैं कि जिसके भीतर संयम नहीं है, उसकी बुद्धि स्थिर नहीं हो सकती। असंयमी व्यक्ति को ध्यान का अनुभव नहीं हो सकता। जिसके पास ध्यान नहीं है, उसे शांति नहीं मिल सकती। और जिसके पास शांति नहीं है, उसके लिए सुख संभव ही नहीं है। यह क्रम बताता है कि आत्मसंयम ही सभी सुख और शांति का मूल आधार है। बिना संयम के जीवन केवल दुःख और अस्थिरता से भरा रहता है।",
    englishMeaning = "For the uncontrolled, there is no steady intellect or meditation. Without meditation, there is no peace, and without peace, how can there be happiness?"
    ),

    Shloka(
    number = 67,
    sanskrit = "इन्द्रियाणां हि चरतां यन्मनोऽनुविधीयते।\nतदस्य हरति प्रज्ञां वायुर्नावमिवाम्भसि॥",
    hindiMeaning = "भगवान कहते हैं कि जब मन इन्द्रियों के पीछे भागता है, तो वह बुद्धि को हर लेता है। जैसे तेज हवा पानी में नाव को इधर-उधर हिला देती है, वैसे ही चंचल इन्द्रियाँ मनुष्य की प्रज्ञा को डगमगा देती हैं। साधक यदि अपने मन को इन्द्रियों के अधीन कर देगा तो उसकी साधना नष्ट हो जाएगी। इसलिए मनुष्य को चाहिए कि वह इन्द्रियों का स्वामी बने, न कि दास। तभी उसकी प्रज्ञा स्थिर और अचल रह सकती है।",
    englishMeaning = "When the mind follows the wandering senses, it carries away wisdom, just as the wind sweeps away a boat on water."
    ),

    Shloka(
    number = 68,
    sanskrit = "तस्माद्यस्य महाबाहो निगृहीतानि सर्वशः।\nइन्द्रियाणीन्द्रियार्थेभ्यस्तस्य प्रज्ञा प्रतिष्ठिता॥",
    hindiMeaning = "हे महाबाहो अर्जुन! जो व्यक्ति अपनी इन्द्रियों को विषयों से पूरी तरह नियंत्रित कर लेता है, उसी की बुद्धि स्थिर होती है। साधना का सार यही है कि मनुष्य अपनी इन्द्रियों को संयमित करे। इन्द्रियाँ जब आत्मा के अधीन होती हैं, तभी वे शांति देती हैं। यदि वे विषयों की ओर दौड़ेंगी तो दुःख ही देंगी। इसलिए स्थिर बुद्धि का रहस्य है – इन्द्रियों पर नियंत्रण।",
    englishMeaning = "O mighty-armed Arjuna, one whose senses are completely restrained from sense objects is firmly established in wisdom."
    ),

    Shloka(
    number = 69,
    sanskrit = "या निशा सर्वभूतानां तस्यां जागर्ति संयमी।\nयस्यां जाग्रति भूतानि सा निशा पश्यतो मुनेः॥",
    hindiMeaning = "भगवान कहते हैं कि जो समय सबके लिए अज्ञान की रात है, उस समय संयमी पुरुष जागता है। और जिसमें सब लोग जागते हैं, वही ज्ञानी पुरुष के लिए रात्रि समान है। इसका अर्थ है कि सामान्य लोग सांसारिक विषयों में लगे रहते हैं, जबकि ज्ञानी व्यक्ति आत्मज्ञान में लीन रहता है। जिसे संसार आकर्षक लगता है, वह आत्मज्ञानी को महत्वहीन प्रतीत होता है। और जिसे ज्ञानी महत्त्वपूर्ण मानता है, उसे सामान्य लोग नहीं समझ पाते। यही ज्ञानी और अज्ञानी के दृष्टिकोण का अंतर है।",
    englishMeaning = "What is night for all beings is the time of wakefulness for the self-controlled sage. And what is wakefulness for all beings is night for the introspective sage."
    ),

    Shloka(
    number = 70,
    sanskrit = "आपूर्यमाणमचलप्रतिष्ठं\nसमुद्रमापः प्रविशन्ति यद्वत्।\nतद्वत्कामा यं प्रविशन्ति सर्वे\nस शान्तिमाप्नोति न कामकामी॥",
    hindiMeaning = "भगवान उदाहरण देते हैं – जैसे समुद्र में नदियाँ निरंतर प्रवाहित होती रहती हैं, फिर भी समुद्र अपनी मर्यादा नहीं तोड़ता और अचल रहता है। वैसे ही जिस व्यक्ति के भीतर असंख्य इच्छाएँ आती हैं परंतु वह स्थिर रहता है, वही शांति प्राप्त करता है। परंतु जो व्यक्ति इच्छाओं का दास है और उन्हें पूरा करने में लगा रहता है, वह कभी शांति नहीं पा सकता। शांति केवल उसी को मिलती है जिसने इच्छाओं को अपने ऊपर हावी नहीं होने दिया।",
    englishMeaning = "As rivers enter the ocean, yet the ocean remains unmoved, so all desires enter into a wise person without disturbing him. But one who seeks desires never attains peace."
    ),

    Shloka(
    number = 71,
    sanskrit = "विहाय कामान्यः सर्वान्पुमांश्चरति निःस्पृहः।\nनिर्ममो निरहंकारः स शान्तिमधिगच्छति॥",
    hindiMeaning = "भगवान कहते हैं कि जो व्यक्ति सभी इच्छाओं को त्यागकर, निरासक्त होकर, ममता और अहंकार से रहित होकर जीवन बिताता है, वही शांति प्राप्त करता है। ममता और अहंकार ही अशांति का कारण हैं। जब साधक इनसे मुक्त हो जाता है, तब वह आत्मा में स्थिर होकर आनंदमय जीवन जीता है। उसकी शांति किसी भी परिस्थिति में डगमगाती नहीं है। यह शांति ही परम धन है।",
    englishMeaning = "He who abandons all desires, lives without craving, free from possessiveness and ego, attains true peace."
    ),

    Shloka(
    number = 72,
    sanskrit = "एषा ब्राह्मी स्थितिः पार्थ नैनां प्राप्य विमुह्यति।\nस्थित्वास्यामन्तकालेऽपि ब्रह्मनिर्वाणमृच्छति॥",
    hindiMeaning = "भगवान कहते हैं कि हे पार्थ! यह ब्राह्मी स्थिति है, इसे प्राप्त करने पर मनुष्य कभी मोह में नहीं पड़ता। यदि कोई अंत समय तक भी इसमें स्थिर रहे तो वह ब्रह्मनिर्वाण, अर्थात् परम मुक्ति को प्राप्त करता है। यह स्थिति वही है जिसमें मनुष्य आत्मा और ब्रह्म में एकत्व का अनुभव करता है। इस अवस्था में मोह, दुख और जन्म-मरण का बंधन समाप्त हो जाता है। यही गीता का सार है – स्थिर बुद्धि और आत्मसाक्षात्कार से मुक्ति।",
    englishMeaning = "This is the divine state, O Arjuna. Attaining it, one is never deluded. Even at the time of death, one established in it reaches liberation in Brahman."
    )
    )

  private  val adhyayaThreeShlokas = listOf(
        Shloka(
            number = 1,
            sanskrit = "अर्जुन उवाच |\nज्यायसी चेत्कर्मणस्ते मता बुद्धिर्जनार्दन।\nतत्किं कर्मणि घोरे मां नियोजयसि केशव॥",
            hindiMeaning = "अर्जुन भगवान से प्रश्न करते हैं कि यदि बुद्धि मार्ग, अर्थात् ज्ञानयोग, कर्म की अपेक्षा श्रेष्ठ माना गया है, तो हे जनार्दन! फिर आप मुझे इस भयंकर युद्ध जैसे कर्म में क्यों लगाते हैं? अर्जुन के मन में द्वंद्व था कि यदि आत्मज्ञान ही सबसे उत्तम है तो फिर कर्म क्यों करना चाहिए। वह यह नहीं समझ पा रहा था कि युद्ध और हिंसा कैसे धर्म हो सकता है। उसके मन में करुणा और मोह का भाव था, इसलिए उसने कृष्ण से स्पष्ट उत्तर माँगा। यह प्रश्न वास्तव में प्रत्येक साधक के भीतर उठता है कि ज्ञान और कर्म में से श्रेष्ठ क्या है।",
            englishMeaning = "Arjuna asks Krishna: If knowledge is superior to action, why do You urge me to engage in this dreadful war? He is confused about why action is necessary if wisdom alone leads to liberation."
        ),

        Shloka(
            number = 2,
            sanskrit = "व्यामिश्रेणेव वाक्येन बुद्धिं मोहयसीव मे।\nतदेकं वद निश्चित्य येन श्रेयोऽहमाप्नुयाम्॥",
            hindiMeaning = "अर्जुन आगे कहता है कि आपके वचनों से मेरी बुद्धि भ्रमित हो रही है। आप कभी ज्ञान की महिमा बताते हैं और कभी कर्म का महत्व समझाते हैं, जिससे मुझे यह निर्णय करना कठिन हो गया है कि वास्तव में कौन सा मार्ग श्रेष्ठ है। इसलिए कृपा करके आप मुझे एक ही मार्ग स्पष्ट रूप से बताइए, जिससे मुझे निश्चित रूप से कल्याण प्राप्त हो सके। अर्जुन का यह निवेदन साधक की उस स्थिति को दर्शाता है जब वह एक साथ अनेक मार्गों से प्रभावित होकर उलझ जाता है। यहाँ अर्जुन ईश्वर से एकमात्र मार्गदर्शन चाहता है।",
            englishMeaning = "Arjuna says: Your words seem contradictory and confuse my understanding. Please tell me one clear path by which I may attain the highest good."
        ),

        Shloka(
            number = 3,
            sanskrit = "श्रीभगवानुवाच |\nलोकेऽस्मिन्द्विविधा निष्ठा पुरा प्रोक्ता मयानघ।\nज्ञानयोगेन सांख्यानां कर्मयोगेन योगिनाम्॥",
            hindiMeaning = "भगवान श्रीकृष्ण उत्तर देते हैं कि हे निष्पाप अर्जुन! मैंने इस संसार में पहले ही दो प्रकार की निष्ठाएँ बताई हैं। सांख्य दर्शन वाले ज्ञानीजन ज्ञानयोग के मार्ग से मुक्ति प्राप्त करते हैं और योगीजन कर्मयोग का पालन करके उन्नति प्राप्त करते हैं। दोनों मार्ग अपने-अपने स्तर के साधकों के लिए हैं। जिनका मन स्थिर और विवेकपूर्ण है, वे ज्ञानयोग में सफल होते हैं। जबकि जिनका स्वभाव सक्रिय और कर्मप्रधान है, उनके लिए कर्मयोग अधिक उपयुक्त है। इस प्रकार भगवान स्पष्ट करते हैं कि दोनों मार्ग आवश्यक हैं।",
            englishMeaning = "Krishna explains that there are two paths: the path of knowledge for contemplative sages, and the path of action for those inclined to activity. Both are valid and lead to spiritual progress."
        ),

        Shloka(
            number = 4,
            sanskrit = "न कर्मणामनारम्भान्नैष्कर्म्यं पुरुषोऽश्नुते।\nन च संन्यसनादेव सिद्धिं समधिगच्छति॥",
            hindiMeaning = "भगवान कहते हैं कि केवल कर्म न करने से मनुष्य निष्कर्मता या मुक्ति को प्राप्त नहीं करता। और केवल संन्यास धारण करने से भी सिद्धि प्राप्त नहीं होती। वास्तविक मुक्ति तो तब होती है जब मनुष्य कर्म करता हुआ भी आसक्ति और फल की इच्छा से मुक्त रहता है। कर्म से भागना या केवल बाह्य त्याग करना वास्तविक त्याग नहीं है। इसलिए अर्जुन को यह समझना चाहिए कि युद्ध से भागकर संन्यास लेने से उसे सिद्धि नहीं मिलेगी।",
            englishMeaning = "One does not attain freedom from action by merely avoiding work, nor does one reach perfection by renunciation alone. True liberation comes through selfless action."
        ),

        Shloka(
            number = 5,
            sanskrit = "न हि कश्चित्क्षणमपि जातु तिष्ठत्यकर्मकृत्।\nकार्यते ह्यवशः कर्म सर्वः प्रकृतिजैर्गुणैः॥",
            hindiMeaning = "भगवान स्पष्ट करते हैं कि इस जगत में कोई भी व्यक्ति एक क्षण भी बिना कर्म किए नहीं रह सकता। प्रत्येक जीव प्रकृति के गुणों के प्रभाव से स्वाभाविक रूप से कर्म करने को विवश है। श्वास लेना, चलना, सोचना – ये सभी कर्म के अंतर्गत आते हैं। इसीलिए कर्म से भागना असंभव है। प्रश्न केवल इतना है कि कर्म स्वार्थपूर्ण किया जाए या निःस्वार्थ भाव से। यदि कर्म भगवान को समर्पित होकर किया जाए तो वही मुक्ति का साधन बन जाता है।",
            englishMeaning = "No one can remain without action even for a moment. Everyone is driven to act by the qualities of nature, whether willingly or unwillingly."
        ),

        Shloka(
            number = 6,
            sanskrit = "कर्मेन्द्रियाणि संयम्य य आस्ते मनसा स्मरन्।\nइन्द्रियार्थान्विमूढात्मा मिथ्याचारः स उच्यते॥",
            hindiMeaning = "श्रीकृष्ण कहते हैं कि जो व्यक्ति बाहर से तो इन्द्रियों को संयमित करता है, लेकिन भीतर ही भीतर विषयों का चिंतन करता रहता है, वह मिथ्याचारी कहलाता है। उसका आचरण पाखंडी है, क्योंकि बाहरी संयम वास्तविक आत्मसंयम नहीं है। यदि मन भीतर से विषयों में रमता है तो इन्द्रिय संयम का कोई मूल्य नहीं है। ऐसा व्यक्ति स्वयं को धोखा देता है और प्रगति नहीं कर सकता। आत्मिक उन्नति के लिए मन और इन्द्रियों का वास्तविक नियंत्रण आवश्यक है।",
            englishMeaning = "One who outwardly restrains the senses but dwells on objects in the mind is a hypocrite. Such self-deception does not lead to spiritual growth."
        ),

        Shloka(
            number = 7,
            sanskrit = "यस्त्विन्द्रियाणि मनसा नियम्यारभतेऽर्जुन।\nकर्मेन्द्रियैः कर्मयोगमसक्तः स विशिष्यते॥",
            hindiMeaning = "भगवान आगे कहते हैं कि जो व्यक्ति मन से इन्द्रियों को नियंत्रित करता है और कर्मों में प्रवृत्त होता है, वही श्रेष्ठ है। वह अपने कर्मेन्द्रियों का प्रयोग करते हुए आसक्ति रहित होकर कर्म करता है। ऐसा साधक बाहरी संयम के साथ-साथ आंतरिक शुद्धता भी रखता है। वह कर्म को भगवान को समर्पित भाव से करता है, न कि फल की लालसा से। इस प्रकार कर्मयोगी ही वास्तविक साधक है।",
            englishMeaning = "But one who controls the senses with the mind and engages in selfless action without attachment is superior. Such a person is a true yogi."
        ),

        Shloka(
            number = 8,
            sanskrit = "नियतं कुरु कर्म त्वं कर्म ज्यायो ह्यकर्मणः।\nशरीरयात्रापि च ते न प्रसिद्ध्येदकर्मणः॥",
            hindiMeaning = "भगवान अर्जुन से कहते हैं कि तुम्हें अपने नियत कर्म अवश्य करने चाहिए, क्योंकि कर्म करना अकर्म से श्रेष्ठ है। यदि मनुष्य कुछ न करे तो उसका शरीर भी नहीं चल सकेगा। शरीर को जीवित रखने के लिए भी कर्म आवश्यक है। इसीलिए युद्ध जैसे कठिन कार्य से भागना उचित नहीं है। नियत कर्म का पालन ही धर्म है और उससे ही प्रगति होती है।",
            englishMeaning = "Perform your prescribed duties, for action is better than inaction. Even the maintenance of the body would not be possible without work."
        ),

        Shloka(
            number = 9,
            sanskrit = "यज्ञार्थात्कर्मणोऽन्यत्र लोकोऽयं कर्मबन्धनः।\nतदर्थं कर्म कौन्तेय मुक्तसङ्गः समाचर॥",
            hindiMeaning = "भगवान कहते हैं कि यदि कर्म यज्ञार्थ अर्थात् भगवान को समर्पित भाव से नहीं किया जाता, तो वह कर्म बंधन का कारण बनता है। लेकिन यदि वही कर्म निःस्वार्थ होकर भगवान के लिए किया जाए तो वह मोक्ष का साधन बन जाता है। इसलिए, हे कौन्तेय! तुम अपने सभी कर्मों को यज्ञभाव से करो और आसक्ति से रहित रहो। इस प्रकार कर्म bondage का कारण न होकर मुक्ति का कारण बन जाएगा।",
            englishMeaning = "Work done as a sacrifice for the Lord frees one from bondage. But work done for selfish purposes binds. Therefore, perform action in a spirit of sacrifice, free from attachment."
        ),

        Shloka(
            number = 10,
            sanskrit = "सहयज्ञाः प्रजाः सृष्ट्वा पुरोवाच प्रजापतिः।\nअनेन प्रसविष्यध्वमेष वोऽस्त्विष्टकामधुक्॥",
            hindiMeaning = "भगवान बताते हैं कि सृष्टि के प्रारंभ में प्रजापति ब्रह्मा ने मनुष्यों और यज्ञ को एक साथ उत्पन्न किया और कहा – 'तुम इस यज्ञ के द्वारा वृद्धि और पोषण पाओगे। यह यज्ञ तुम्हारी सभी कामनाओं को पूर्ण करने वाला होगा।' इसका अर्थ है कि कर्म और यज्ञ मानव जीवन के अभिन्न अंग हैं। यज्ञ का तात्पर्य केवल अग्नि में आहुति देना नहीं है, बल्कि निःस्वार्थ भाव से किया गया प्रत्येक कार्य यज्ञ है। यही कर्म का शुद्ध स्वरूप है।",
            englishMeaning = "In the beginning, the Creator made mankind along with sacrifice and said: 'By sacrifice you shall prosper, and sacrifice will fulfill your desires.'"
        ),
        Shloka(
            number = 11,
            sanskrit = "देवान्भावयतानेन ते देवा भावयन्तु वः।\nपरस्परं भावयन्तः श्रेयः परमवाप्स्यथ॥",
            hindiMeaning = "भगवान कहते हैं कि इस यज्ञभाव से तुम देवताओं को प्रसन्न करो और देवता तुम्हें प्रसन्न करेंगे। इस प्रकार परस्पर सहयोग से तुम परम कल्याण को प्राप्त करोगे। यहाँ 'देवता' का अर्थ केवल देवस्वरूप शक्तियों से नहीं, बल्कि वे सब दिव्य शक्तियाँ हैं जो सृष्टि के संचालन में सहायक हैं। मनुष्य जब अपने कर्मों को निःस्वार्थ और समर्पण भाव से करता है, तो वह प्रकृति और समाज के संतुलन को बनाए रखता है। इसके बदले में प्रकृति और समाज उसे आवश्यक सहयोग और साधन प्रदान करते हैं। यही संतुलन जीवन को सुखी और उन्नत बनाता है।",
            englishMeaning = "By sacrifice, you nourish the gods, and they will nourish you in return. Thus, by mutual cooperation, you shall attain the highest good."
        ),

        Shloka(
            number = 12,
            sanskrit = "इष्टान्भोगान्हि वो देवा दास्यन्ते यज्ञभाविताः।\nतैर्दत्तानप्रदायैभ्यो यो भुङ्क्ते स्तेन एव सः॥",
            hindiMeaning = "भगवान कहते हैं कि यज्ञ से प्रसन्न होकर देवता तुम्हें इच्छित भोग देंगे। लेकिन जो व्यक्ति इन देवताओं द्वारा दिए गए संसाधनों का उपयोग करता है और बदले में कुछ नहीं लौटाता, वह वास्तव में चोर है। यहाँ चोर का अर्थ है – वह जो केवल लेता है और देता कुछ नहीं। प्रकृति, समाज और ईश्वर से प्राप्त उपकारों का प्रतिदान न करके जो केवल अपने स्वार्थ के लिए उनका उपभोग करता है, वह अधर्म करता है। इसीलिए मनुष्य को हमेशा निःस्वार्थ भाव से यज्ञ और सेवा करनी चाहिए।",
            englishMeaning = "The gods will provide you with desired needs when pleased by sacrifice. But one who enjoys these gifts without offering back is a thief."
        ),

        Shloka(
            number = 13,
            sanskrit = "यज्ञशिष्टाशिनः सन्तो मुच्यन्ते सर्वकिल्बिषैः।\nभुञ्जते ते त्वघं पापा ये पचन्त्यात्मकारणात्॥",
            hindiMeaning = "भगवान कहते हैं कि जो संत यज्ञशेष अन्न का सेवन करते हैं, वे सभी पापों से मुक्त हो जाते हैं। लेकिन जो लोग केवल अपने लिए, स्वार्थवश भोजन पकाते हैं, वे पाप का भक्षण करते हैं। यज्ञशेष अन्न का तात्पर्य है वह भोजन या संसाधन जिसे भगवान को अर्पित करके ग्रहण किया जाए। जब हम निःस्वार्थ भाव से भगवान को अर्पण करते हैं, तो वह अन्न पवित्र बन जाता है। लेकिन केवल स्वार्थ के लिए किया गया उपभोग मनुष्य को बंधन और पाप की ओर ले जाता है।",
            englishMeaning = "The righteous who eat what remains from sacrifice are freed from all sins. But those who cook only for themselves eat only sin."
        ),

        Shloka(
            number = 14,
            sanskrit = "अन्नाद्भवन्ति भूतानि पर्जन्यादन्नसम्भवः।\nयज्ञाद्भवति पर्जन्यो यज्ञः कर्मसमुद्भवः॥",
            hindiMeaning = "भगवान यहाँ सृष्टि का शाश्वत नियम बताते हैं। सभी प्राणी अन्न से उत्पन्न होते हैं, अन्न वर्षा से उत्पन्न होता है, वर्षा यज्ञ से होती है और यज्ञ कर्म से उत्पन्न होता है। इसका अर्थ यह है कि संपूर्ण जीवन चक्र परस्पर एक-दूसरे पर आधारित है। यदि मनुष्य निःस्वार्थ कर्म और यज्ञ करेगा तो वर्षा और अन्न की समृद्धि बनी रहेगी। लेकिन यदि वह स्वार्थी होकर प्रकृति के नियमों की उपेक्षा करेगा, तो संतुलन बिगड़ जाएगा। यह गीता का गहरा पर्यावरणीय और सामाजिक संदेश है।",
            englishMeaning = "All beings are sustained by food, food comes from rain, rain from sacrifice, and sacrifice arises from prescribed action. Thus, life is sustained by selfless work."
        ),

        Shloka(
            number = 15,
            sanskrit = "कर्म ब्रह्मोद्भवं विद्धि ब्रह्माक्षरसमुद्भवम्।\nतस्मात्सर्वगतं ब्रह्म नित्यं यज्ञे प्रतिष्ठितम्॥",
            hindiMeaning = "भगवान कहते हैं कि कर्म वेदों से उत्पन्न है और वेद अविनाशी ब्रह्म से उत्पन्न हैं। इसलिए कर्म का आधार ब्रह्म है और ब्रह्म सदा यज्ञ में प्रतिष्ठित है। इसका तात्पर्य है कि समस्त कर्म अंततः दिव्य नियमों से जुड़े हुए हैं। जब हम यज्ञभाव से कर्म करते हैं, तब हम वास्तव में ईश्वर की इच्छा का पालन करते हैं। इसीलिए प्रत्येक कर्म को पवित्र मानकर भगवान को अर्पित करना चाहिए।",
            englishMeaning = "Know that action arises from the Vedas, and the Vedas come from the imperishable Brahman. Therefore, the all-pervading Brahman is eternally present in sacrifice."
        ),

        Shloka(
            number = 16,
            sanskrit = "एवं प्रवर्तितं चक्रं नानुवर्तयतीह यः।\nअघायुरिन्द्रियारामो मोघं पार्थ स जीवति॥",
            hindiMeaning = "भगवान कहते हैं कि इस प्रकार सृष्टि का यह चक्र – यज्ञ, वर्षा, अन्न और जीवन – जो दिव्य नियमों से स्थापित हुआ है, यदि कोई उसका पालन नहीं करता, तो वह व्यर्थ जीता है। ऐसा व्यक्ति पापमय जीवन जीता है और केवल इन्द्रियों की तृप्ति में लिप्त रहता है। उसका जीवन केवल भोग और स्वार्थ तक सीमित होता है। लेकिन ऐसा जीवन न स्वयं के लिए कल्याणकारी होता है, न ही समाज और प्रकृति के लिए। इसीलिए इस चक्र का पालन करना प्रत्येक मनुष्य का कर्तव्य है।",
            englishMeaning = "He who does not follow the divine cycle of sacrifice lives in sin, delighting only in the senses. O Arjuna, such a life is wasted."
        ),

        Shloka(
            number = 17,
            sanskrit = "यस्त्वात्मरतिरेव स्यादात्मतृप्तश्च मानवः।\nआत्मन्येव च सन्तुष्टस्तस्य कार्यं न विद्यते॥",
            hindiMeaning = "भगवान कहते हैं कि जो मनुष्य आत्मा में ही आनंदित है, आत्मा में ही तृप्त है और आत्मा में ही संतुष्ट है, उसके लिए कोई भी कर्म करना शेष नहीं रहता। ऐसा व्यक्ति बाहरी भोग और साधनों पर निर्भर नहीं होता। उसकी शांति और आनंद केवल आत्मज्ञान से ही पूर्ण होती है। इसलिए उसे किसी बाहरी कर्तव्य की आवश्यकता नहीं है। यह अवस्था केवल परम ज्ञानी और सिद्ध पुरुषों के लिए संभव है।",
            englishMeaning = "But the person who delights in the self, is satisfied in the self, and is content in the self alone, has no duty to perform."
        ),

        Shloka(
            number = 18,
            sanskrit = "नैव तस्य कृतेनार्थो नाकृतेनेह कश्चन।\nन चास्य सर्वभूतेषु कश्चिदर्थव्यपाश्रयः॥",
            hindiMeaning = "भगवान आगे कहते हैं कि ऐसे आत्मतृप्त पुरुष का न तो किए गए कर्मों से कोई लाभ है और न ही कर्म न करने से कोई हानि। वह किसी भी प्राणी या वस्तु पर आश्रित नहीं होता। उसका जीवन पूर्ण स्वतंत्रता और आत्मनिर्भरता से युक्त होता है। उसका सुख और शांति किसी बाहरी साधन पर आधारित नहीं होता। इस प्रकार वह सच्चा मुक्त आत्मा होता है।",
            englishMeaning = "For such a self-realized person, there is nothing to gain from action or inaction, nor does he depend on any being for anything."
        ),

        Shloka(
            number = 19,
            sanskrit = "तस्मादसक्तः सततं कार्यं कर्म समाचर।\nअसक्तो ह्याचरन्कर्म परमाप्नोति पूरुषः॥",
            hindiMeaning = "भगवान अर्जुन से कहते हैं कि इसलिए तुम आसक्ति रहित होकर सदा अपने नियत कर्म करो। जब मनुष्य आसक्ति रहित होकर कर्म करता है, तो वह परम सिद्धि को प्राप्त करता है। कर्म से भागना नहीं, बल्कि उसे निःस्वार्थ भाव से करना ही मोक्ष का साधन है। ऐसे कर्म से व्यक्ति समाज का कल्याण भी करता है और आत्मा को भी शुद्ध करता है। यही कर्मयोग का मूल सिद्धांत है।",
            englishMeaning = "Therefore, perform your duty without attachment. By working without attachment, a person attains the Supreme."
        ),

        Shloka(
            number = 20,
            sanskrit = "कर्मणैव हि संसिद्धिमास्थिता जनकादयः।\nलोकसंग्रहमेवापि सम्पश्यन्कर्तुमर्हसि॥",
            hindiMeaning = "भगवान कहते हैं कि जनक आदि राजाओं ने केवल कर्म के द्वारा ही सिद्धि प्राप्त की थी। वे राजकार्य करते हुए भी आत्मज्ञानी और मुक्त थे। इसलिए हे अर्जुन! तुम्हें भी लोकसंग्रह अर्थात् समाज के कल्याण के लिए कर्म करना चाहिए। जब ज्ञानी व्यक्ति समाज के लिए कर्म करता है, तो लोग उसका अनुकरण करते हैं और धर्म का पालन करते हैं। इस प्रकार कर्मयोग केवल व्यक्तिगत मोक्ष ही नहीं, बल्कि सामूहिक कल्याण का मार्ग भी है।",
            englishMeaning = "Perfection was attained by kings like Janaka through action alone. Therefore, you too should perform action, keeping in mind the welfare of the world."
        ),

        Shloka(
            number = 21,
            sanskrit = "यद्यदाचरति श्रेष्ठस्तत्तदेवेतरो जनः।\nस यत्प्रमाणं कुरुते लोकस्तदनुवर्तते॥",
            hindiMeaning = "भगवान कहते हैं कि श्रेष्ठ पुरुष जो भी आचरण करता है, सामान्य लोग उसका अनुसरण करते हैं। समाज हमेशा अपने आदर्शों को देखकर प्रेरणा लेता है। इसलिए यदि नेता, गुरु या ज्ञानी व्यक्ति धर्म और कर्तव्य का पालन करता है, तो अन्य लोग भी वही मार्ग अपनाते हैं। इस कारण श्रेष्ठ लोगों की जिम्मेदारी और बढ़ जाती है। यदि वे गलत मार्ग अपनाएँगे तो समाज भी भटक जाएगा। इसलिए अर्जुन! तुम्हें अपना आचरण आदर्श बनाना चाहिए ताकि लोग तुम्हारे उदाहरण से प्रेरणा लें।",
            englishMeaning = "Whatever a great person does, others follow. People look up to their leaders as examples and act accordingly."
        ),

        Shloka(
            number = 22,
            sanskrit = "न मे पार्थास्ति कर्तव्यं त्रिषु लोकेषु किञ्चन।\nनानवाप्तमवाप्तव्यं वर्त एव च कर्मणि॥",
            hindiMeaning = "भगवान कहते हैं कि हे पार्थ! तीनों लोकों में मेरे लिए कोई कर्तव्य नहीं है। मुझे कुछ प्राप्त करना शेष नहीं है और न ही कुछ अप्राप्त रह गया है। फिर भी मैं कर्म में निरंतर लगा रहता हूँ। इसका कारण यह है कि ईश्वर स्वयं कर्म करके संसार को आदर्श दिखाते हैं। यदि ईश्वर भी निष्क्रिय हो जाएँ तो सृष्टि का संचालन ही रुक जाएगा। इस प्रकार भगवान स्वयं कर्म के महत्व को प्रत्यक्ष रूप से दिखाते हैं।",
            englishMeaning = "O Arjuna, I have nothing to gain or achieve in all the three worlds, yet I am always engaged in action."
        ),

        Shloka(
            number = 23,
            sanskrit = "यदि ह्यहं न वर्तेयं जातु कर्मण्यतन्द्रितः।\nमम वर्त्मानुवर्तन्ते मनुष्याः पार्थ सर्वशः॥",
            hindiMeaning = "भगवान कहते हैं कि यदि मैं कभी भी कर्म में तत्पर न रहूँ, तो लोग भी मेरी ही तरह आलसी और निष्क्रिय हो जाएँगे। मनुष्य ईश्वर और महान व्यक्तियों को देखकर ही अपने आचरण का निर्धारण करता है। यदि ईश्वर स्वयं निष्क्रिय रहते, तो मनुष्य भी कर्तव्य का पालन छोड़ देता। इससे संसार का संतुलन बिगड़ जाता। इसलिए भगवान निरंतर कर्म में लगे रहते हैं ताकि लोग धर्म और कर्म का पालन करना न भूलें।",
            englishMeaning = "If I did not engage in action, O Arjuna, people would follow my example and stop acting as well."
        ),

        Shloka(
            number = 24,
            sanskrit = "उत्सीदेयुरिमे लोका न कुर्यां कर्म चेदहम्।\nसङ्करस्य च कर्ता स्यामुपहन्यामिमाः प्रजाः॥",
            hindiMeaning = "भगवान कहते हैं कि यदि मैं कर्म न करूँ, तो ये सभी लोक नष्ट हो जाएँगे। मैं समाज में अव्यवस्था और अधर्म का कारण बनूँगा। इससे प्रजा का विनाश हो जाएगा और जीवन का क्रम रुक जाएगा। इसलिए ईश्वर स्वयं भी कर्म करके सृष्टि का संचालन करते हैं। इस श्लोक से यह स्पष्ट होता है कि कर्म का त्याग करना विनाश का कारण है। कर्म का पालन करना ही जीवन और समाज को बनाए रखता है।",
            englishMeaning = "If I did not act, these worlds would perish. Disorder would prevail, and beings would be destroyed."
        ),

        Shloka(
            number = 25,
            sanskrit = "सक्ताः कर्मण्यविद्वांसो यथा कुर्वन्ति भारत।\nकुर्याद्विद्वांस्तथासक्तश्चिकीर्षुर्लोकसंग्रहम्॥",
            hindiMeaning = "भगवान कहते हैं कि हे भारत! अज्ञानी लोग आसक्ति से कर्म करते हैं, लेकिन ज्ञानी व्यक्ति भी आसक्ति रहित होकर कर्म करता है। वह कर्म इसलिए करता है ताकि संसार में संतुलन बना रहे और लोग उसका अनुसरण करें। ज्ञानी व्यक्ति जानता है कि आत्मा निर्लिप्त है, फिर भी वह लोकसंग्रह यानी समाज के कल्याण के लिए कर्म करता है। इस प्रकार ज्ञानी और अज्ञानी दोनों कर्म करते हैं, परंतु उनके भाव अलग होते हैं।",
            englishMeaning = "As the ignorant act with attachment, so should the wise act without attachment, for the welfare of the world."
        ),

        Shloka(
            number = 26,
            sanskrit = "न बुद्धिभेदं जनयेदज्ञानां कर्मसङ्गिनाम्।\nजोषयेत्सर्वकर्माणि विद्वान्युक्तः समाचरन्॥",
            hindiMeaning = "भगवान कहते हैं कि ज्ञानी को चाहिए कि अज्ञानियों में बुद्धिभेद न उत्पन्न करे। अर्थात् उन्हें कर्म के प्रति भ्रमित न करे। ज्ञानी स्वयं निःस्वार्थ कर्म करता हुआ उन्हें भी धीरे-धीरे सही मार्ग की ओर प्रेरित करे। यदि ज्ञानी अचानक कहे कि कर्म छोड़ दो, तो अज्ञानी लोग गलत मार्ग पर चल पड़ेंगे। इसलिए ज्ञानी को व्यवहार में सहजता रखनी चाहिए और धीरे-धीरे दूसरों को यथार्थ समझाना चाहिए।",
            englishMeaning = "The wise should not unsettle the minds of the ignorant attached to action. Instead, by performing action diligently, they should inspire others."
        ),

        Shloka(
            number = 27,
            sanskrit = "प्रकृतेः क्रियमाणानि गुणैः कर्माणि सर्वशः।\nअहङ्कारविमूढात्मा कर्ताहमिति मन्यते॥",
            hindiMeaning = "भगवान कहते हैं कि सभी कर्म प्रकृति के गुणों द्वारा किए जाते हैं। परंतु अहंकार से मोहित मनुष्य सोचता है कि 'मैं ही कर्ता हूँ।' वास्तव में आत्मा कर्म का कर्ता नहीं है, बल्कि प्रकृति के तीन गुण – सत्त्व, रज और तम – ही कर्म कराते हैं। अज्ञानवश मनुष्य स्वयं को कर्ता मान लेता है और इसी से बंधन उत्पन्न होता है। आत्मज्ञान होने पर यह भ्रम मिट जाता है और व्यक्ति मुक्त हो जाता है।",
            englishMeaning = "All actions are performed by the modes of material nature. But the deluded soul thinks, 'I am the doer.'"
        ),

        Shloka(
            number = 28,
            sanskrit = "तत्त्ववित्तु महाबाहो गुणकर्मविभागयोः।\nगुणा गुणेषु वर्तन्त इति मत्वा न सज्जते॥",
            hindiMeaning = "भगवान कहते हैं कि हे महाबाहु! जो तत्वज्ञानी है, वह गुण और कर्म के भेद को जानता है। वह समझता है कि केवल प्रकृति के गुण ही गुणों में कार्य कर रहे हैं। इसलिए वह उनमें आसक्त नहीं होता। ऐसा ज्ञानी व्यक्ति जानता है कि आत्मा इन सब कर्मों से परे और शुद्ध है। इस समझ के कारण वह निर्लिप्त और शांत रहता है।",
            englishMeaning = "But the one who knows the truth understands that the senses act among the sense objects, and thus he is not attached."
        ),

        Shloka(
            number = 29,
            sanskrit = "प्रकृतेर्गुणसम्मूढाः सज्जन्ते गुणकर्मसु।\nतानकृत्स्नविदो मन्दान्कृत्स्नविन्न विचालयेत्॥",
            hindiMeaning = "भगवान कहते हैं कि जो लोग प्रकृति के गुणों से मोहित होते हैं, वे गुण और कर्म में आसक्त हो जाते हैं। वे अज्ञान के कारण कर्म में फँस जाते हैं। ज्ञानी को चाहिए कि ऐसे अज्ञानी लोगों को विचलित न करे। बल्कि धीरे-धीरे उन्हें शिक्षा दे और उनकी समझ के अनुसार मार्गदर्शन करे। यदि उन्हें अचानक पूर्ण ज्ञान दिया जाए तो वे भ्रमित हो सकते हैं। इसलिए धैर्य और करुणा के साथ उन्हें कर्मयोग की ओर प्रेरित करना चाहिए।",
            englishMeaning = "Those who are deluded by the modes of nature become attached to their actions. The wise should not disturb them but guide them gently."
        ),

        Shloka(
            number = 30,
            sanskrit = "मयि सर्वाणि कर्माणि संन्यस्याध्यात्मचेतसा।\nनिराशीर्निर्ममो भूत्वा युध्यस्व विगतज्वरः॥",
            hindiMeaning = "भगवान कहते हैं कि हे अर्जुन! अपने सभी कर्म मुझे अर्पित कर दो और अपने मन को आध्यात्मिक चेतना में स्थिर करो। आशा और ममता का त्याग करके युद्ध करो। ऐसा करने पर तुम्हारे भीतर कोई मानसिक क्लेश या संशय नहीं रहेगा। जब मनुष्य अपने कर्म को ईश्वर को अर्पित कर देता है, तो वह मुक्त हो जाता है। इस प्रकार कर्तव्य का पालन करते हुए भी आत्मा बंधन से परे रहती है।",
            englishMeaning = "Surrender all your actions to me with a spiritual mind. Fight without desire or attachment, free from mental agitation."
        ),
        Shloka(
            number = 31,
            sanskrit = "ये मे मतमिदं नित्यमनुतिष्ठन्ति मानवाः।\nश्रद्धावन्तोऽनसूयन्तो मुच्यन्ते तेऽपि कर्मभिः॥",
            hindiMeaning = "भगवान कहते हैं कि जो लोग मेरे इस मत का नित्य पालन करते हैं, श्रद्धा रखते हैं और दोषदृष्टि नहीं करते, वे भी कर्मों से मुक्त हो जाते हैं। श्रद्धा यहाँ अत्यंत महत्वपूर्ण है क्योंकि बिना विश्वास के कोई भी साधना सफल नहीं हो सकती। जब मनुष्य ईश्वर की आज्ञा को सर्वोच्च मानकर अपने कर्म करता है, तब उसके कर्म बंधनरहित हो जाते हैं। ऐसा व्यक्ति जीवन में शांति और मुक्ति की ओर अग्रसर होता है। इस श्लोक में स्पष्ट है कि केवल ज्ञान ही नहीं, बल्कि श्रद्धा और समर्पण भी आवश्यक हैं।",
