            sanskrit = "न तु मां शक्यसे द्रष्टुमनेनैव स्वचक्षुषा ।\nदिव्यं ददामि ते चक्षुः पश्य मे योगमैश्वरम् ॥",
            hindiMeaning = "भगवान कहते हैं – परंतु हे अर्जुन! तुम मुझे अपने इन सामान्य नेत्रों से नहीं देख सकते। इसलिए मैं तुम्हें दिव्य दृष्टि प्रदान करता हूँ, जिससे तुम मेरे इस ऐश्वर्यपूर्ण योग को देख सको। यह श्लोक अत्यंत महत्वपूर्ण है, क्योंकि यह बताता है कि परमात्मा के विराट रूप का दर्शन साधारण इंद्रियों से संभव नहीं। साधक को इसके लिए दिव्य अनुभूति और ईश्वर की विशेष कृपा की आवश्यकता होती है। यहाँ भगवान स्वयं अर्जुन को वह शक्ति दे रहे हैं, जिससे वे असाधारण अनुभव कर सकें। यह संदेश हमें यह सिखाता है कि जब तक भगवान की कृपा नहीं होती, तब तक हम केवल सीमित दृष्टि से ही संसार को देख पाते हैं।",
            englishMeaning = "But you cannot see Me with your present eyes. Therefore I give you divine vision; behold My majestic power of Yoga."
        ),
        Shloka(
            number = 9,
            sanskrit = "सञ्जय उवाच ।\nएवमुक्त्वा ततो राजन्महायोगेश्वरो हरिः ।\nदर्शयामास पार्थाय परमं रूपमैश्वरम् ॥",
            hindiMeaning = "संजय कहते हैं – हे राजन धृतराष्ट्र! इस प्रकार कहकर महायोगेश्वर भगवान श्रीकृष्ण ने अर्जुन को अपना परम ऐश्वर्यपूर्ण रूप दिखाया। यह श्लोक गवाह है उस अद्वितीय घटना का जिसमें भगवान ने अपने विराट रूप का प्रत्यक्ष दर्शन कराया। ‘महायोगेश्वर’ शब्द यह बताता है कि भगवान योग और शक्ति के स्वामी हैं, वे अपनी इच्छा से ही ऐसे दिव्य रूप प्रकट कर सकते हैं। इस क्षण में अर्जुन का भाग्य जागृत हुआ और उन्हें वह दृष्टि मिली जो किसी साधारण प्राणी के लिए असंभव है। यह घटना बताती है कि जब ईश्वर चाहते हैं, तभी भक्त उनके स्वरूप का अनुभव कर पाता है।",
            englishMeaning = "Sanjaya said: O King, having spoken thus, the great Lord of Yoga, Hari, then revealed to Arjuna His supreme and majestic form."
        ),
        Shloka(
            number = 10,
            sanskrit = "अनेकवक्त्रनयनमनेकाद्भुतदर्शनम् ।\nअनेकदिव्याभरणं दिव्यानेकोद्यतायुधम् ॥",
            hindiMeaning = "संजय कहते हैं – अर्जुन ने भगवान के उस विराट रूप को देखा जिसमें अनेक मुख और नेत्र थे, अनेक अद्भुत दृश्य थे, अनेक दिव्य आभूषण थे और अनेक दिव्य अस्त्र-शस्त्र धारण किए हुए थे। यह श्लोक दर्शाता है कि ईश्वर का विराट स्वरूप अत्यंत अद्भुत और मानव की कल्पना से परे है। यहाँ ‘अनेकवक्त्रनयनम्’ से स्पष्ट होता है कि भगवान का स्वरूप सीमित नहीं, बल्कि असंख्य आयामों वाला है। साधारण मनुष्य के लिए यह दृश्य विस्मयकारी और भयमिश्रित होता है। इससे यह शिक्षा मिलती है कि ईश्वर की महिमा को नापने का प्रयास व्यर्थ है, क्योंकि उनका स्वरूप अनंत और दिव्य है।",
            englishMeaning = "With many mouths and eyes, with many wondrous sights, adorned with many divine ornaments, and wielding many divine weapons, He appeared."
        ),Shloka(
            number = 11,
            sanskrit = "दिव्यमाल्याम्बरधरं दिव्यमाल्यायुधं शुभम् ।\nदिव्यगन्धानुलेपनं सर्वाश्चर्यमयं हरिम् ॥",
            hindiMeaning = "संजय कहते हैं – भगवान का वह विराट रूप दिव्य मालाओं और वस्त्रों से सुसज्जित था। वे दिव्य गहनों और आभूषणों से अलंकृत थे और दिव्य सुगंधित लेप से शोभित हो रहे थे। वह सम्पूर्ण स्वरूप आश्चर्यजनक और अद्भुत था। इस श्लोक में भगवान के विराट रूप का अलंकारिक और सौंदर्यमय पक्ष प्रस्तुत है। साधारण मानव शरीर की सीमाएँ जहाँ समाप्त हो जाती हैं, वहाँ भगवान का स्वरूप अनंत वैभव और सौंदर्य से भरा हुआ है। इस अद्वितीय दृश्य ने अर्जुन के मन में विस्मय और गहन भक्ति उत्पन्न कर दी। यहाँ यह शिक्षा मिलती है कि परमात्मा का स्वरूप केवल शक्ति का ही नहीं बल्कि अपार सौंदर्य और आकर्षण का भी प्रतीक है।",
            englishMeaning = "He was adorned with divine garlands and garments, anointed with heavenly fragrances, resplendent, and wondrous in every way."
        ),
        Shloka(
            number = 12,
            sanskrit = "दिवि सूर्यसहस्रस्य भवेद्युगपदुत्थिता ।\nयदि भाः सदृशी सा स्याद्भासस्तस्य महात्मनः ॥",
            hindiMeaning = "संजय कहते हैं – यदि आकाश में सहस्र सूर्यों का प्रकाश एक साथ उदय हो जाए, तो वह भगवान के विराट रूप की ज्योति के समान हो सकता है। इस श्लोक में ईश्वर के प्रकाश और तेज का वर्णन है। साधारण सूर्य की भी चमक सहन करना कठिन होता है, तो सोचिए सहस्र सूर्य का तेज कितना अद्भुत होगा। लेकिन भगवान का स्वरूप उस तेज से भी परे है। यह दिव्यता केवल भौतिक प्रकाश नहीं है, बल्कि आत्मा को झकझोर देने वाली आध्यात्मिक ऊर्जा है। यहाँ अर्जुन को यह एहसास हो रहा था कि वे परम सत्य के साक्षात्कार में खड़े हैं।",
            englishMeaning = "If a thousand suns were to rise in the sky at once, their brilliance might resemble the radiance of that great Being."
        ),
        Shloka(
            number = 13,
            sanskrit = "तत्रैकस्थं जगत्कृत्स्नं प्रविभक्तमनेकधा ।\nअपश्यद्देवदेवस्य शरीरे पाण्डवस्तदा ॥",
            hindiMeaning = "संजय कहते हैं – उस समय पाण्डव अर्जुन ने भगवान के शरीर में समस्त ब्रह्मांड को एक स्थान पर देखा, यद्यपि वह अनेक रूपों में विभक्त था। यहाँ यह स्पष्ट किया जा रहा है कि विराट रूप में सम्पूर्ण जगत विद्यमान है। चल और अचल सबकुछ भगवान में ही स्थित है। यह अनुभव किसी भी साधक के लिए अत्यंत अद्भुत होता है, क्योंकि वह प्रत्यक्ष देखता है कि समस्त ब्रह्मांड ईश्वर में समाहित है। इससे यह शिक्षा मिलती है कि ब्रह्मांड और ईश्वर अलग नहीं हैं; सृष्टि का आधार स्वयं परमात्मा ही हैं।",
            englishMeaning = "Then Arjuna saw the entire universe, with its many divisions, gathered together in the body of the God of gods."
        ),
        Shloka(
            number = 14,
            sanskrit = "ततः स विस्मयाविष्टो हृष्टरोमा धनञ्जयः ।\nप्रणम्य शिरसा देवं कृताञ्जलिरभाषत ॥",
            hindiMeaning = "संजय कहते हैं – तत्पश्चात अर्जुन विस्मय से भर गए और उनके रोमांच खड़े हो गए। उन्होंने भगवान को प्रणाम किया और हाथ जोड़कर आदरपूर्वक कहा। इस श्लोक में अर्जुन के मनोभाव का वर्णन है। अब तक वे शिष्य और मित्र की तरह भगवान से संवाद कर रहे थे, परंतु विराट रूप के दर्शन ने उनमें भय, श्रद्धा और उत्साह का अद्भुत मिश्रण पैदा कर दिया। उन्होंने सहज ही अपना सिर झुका दिया और हाथ जोड़ दिए। इससे यह शिक्षा मिलती है कि ईश्वर के वास्तविक स्वरूप के अनुभव से मनुष्य के भीतर का अहंकार स्वतः नष्ट हो जाता है और वह केवल भक्ति और समर्पण से भर जाता है।",
            englishMeaning = "Filled with wonder, his hair standing on end, Arjuna bowed his head to the Lord, and with folded hands he spoke."
        ),
        Shloka(
            number = 15,
            sanskrit = "अर्जुन उवाच ।\nपश्यामि देवांस्तव देव देहे सर्वांस्तथा भूतविशेषसङ्घान् ।\nब्रह्माणमीशं कमलासनस्थमृषींश्च सर्वानुरगांश्च दिव्यान् ॥",
            hindiMeaning = "अर्जुन ने कहा – हे देव! मैं आपके शरीर में सभी देवताओं को देख रहा हूँ। साथ ही सभी प्रकार के प्राणियों के समूहों को भी देख रहा हूँ। मैं ब्रह्माजी को कमलासन पर बैठे हुए देख रहा हूँ, शिवजी को देख रहा हूँ और सभी ऋषियों और दिव्य नागों को भी देख रहा हूँ। यहाँ अर्जुन विस्तार से बता रहे हैं कि भगवान के विराट रूप में सभी देवता और महान ऋषि सम्मिलित हैं। यह केवल किसी कल्पना का अनुभव नहीं था, बल्कि प्रत्यक्ष अनुभूति थी। इससे यह स्पष्ट होता है कि ईश्वर का स्वरूप संपूर्ण सृष्टि और सभी दैवी शक्तियों का मूल आधार है। साधक के लिए यह संदेश है कि जब वह ईश्वर के रूप का चिंतन करता है, तो उसे समझना चाहिए कि सभी देवता और ऋषि वास्तव में उसी विराट शक्ति के अंग हैं।",
            englishMeaning = "Arjuna said: O Lord, within Your body I see all the gods, and all kinds of beings. I see Brahma seated on the lotus, Shiva, the sages, and the celestial serpents."
        ),
        Shloka(
            number = 16,
            sanskrit = "अनेकबाहूदरवक्त्रनेत्रं पश्यामि त्वां सर्वतोऽनन्तरूपम् ।\nनान्तं न मध्यं न पुनस्तवादिं पश्यामि विश्वेश्वर विश्वरूप ॥",
            hindiMeaning = "अर्जुन कहते हैं – हे विश्वेश्वर! मैं आपके अनेक भुजाएँ, उदर, मुख और नेत्र देख रहा हूँ। आपका रूप सब ओर फैला हुआ है। मुझे आपका न कोई अंत दिखाई देता है, न मध्य और न ही आरंभ। यह श्लोक ईश्वर के अनंत स्वरूप की झलक देता है। मनुष्य हर चीज़ को शुरुआत और अंत के आधार पर समझता है, परंतु ईश्वर समय और स्थान की सीमा से परे हैं। यहाँ अर्जुन ने स्वीकार किया कि भगवान का रूप अनंत है और उसे मापना या समझना असंभव है। यह शिक्षा साधक को विनम्रता प्रदान करती है कि परमात्मा के सामने उसका ज्ञान और शक्ति सीमित है।",
            englishMeaning = "I see You with infinite forms, with many arms, stomachs, mouths, and eyes. O Lord of the universe, I see no end, no middle, and no beginning of You."
        ),
        Shloka(
            number = 17,
            sanskrit = "किरिटिनं गदिनं चक्रिणं च तेजोराशिं सर्वतो दीप्तिमन्तम् ।\nपश्यामि त्वां दुर्निरीक्ष्यं समन्ताद्दीप्तानलार्कद्युतिमप्रमेयम् ॥",
            hindiMeaning = "अर्जुन कहते हैं – मैं आपको मुकुटधारी, गदा और चक्र धारण किए हुए देख रहा हूँ। आप चारों ओर से प्रकाश की किरणों से युक्त हैं। आपका तेज अग्नि और सूर्य की भाँति दाहक और देखने में कठिन है। आप अपरिमेय हैं। इस श्लोक में भगवान के शस्त्रधारी और तेजस्वी स्वरूप का वर्णन है। यह केवल सौंदर्यपूर्ण रूप नहीं, बल्कि शक्ति और प्रचंड ऊर्जा का प्रतीक है। अर्जुन यहाँ अनुभव कर रहे हैं कि भगवान का रूप सहन करना आसान नहीं है। इससे यह शिक्षा मिलती है कि परमात्मा केवल दयालु ही नहीं, बल्कि अनंत शक्ति के भी प्रतीक हैं।",
            englishMeaning = "I see You crowned, armed with mace and discus, shining everywhere with radiance like blazing fire and the sun, hard to behold, immeasurable."
        ),
        Shloka(
            number = 18,
            sanskrit = "त्वमक्षरं परमं वेदितव्यं त्वमस्य विश्वस्य परं निधानम् ।\nत्वमव्ययः शाश्वतधर्मगोप्ता सनातनस्त्वं पुरुषो मतो मे ॥",
            hindiMeaning = "अर्जुन कहते हैं – आप ही वह अक्षर हैं, जो परम सत्य है और जानने योग्य है। आप इस विश्व का परम आधार हैं। आप अविनाशी हैं, सनातन धर्म के रक्षक हैं और सनातन पुरुष हैं। यहाँ अर्जुन स्वीकार कर रहे हैं कि ईश्वर ही वह परब्रह्म हैं जिनका वेदों में वर्णन है। वे ही सबके पालनकर्ता और धर्म के संरक्षक हैं। यह श्लोक साधक को बताता है कि ईश्वर का स्वरूप समय और स्थान की सीमा से परे है। वह नित्य, शाश्वत और धर्म का परम आधार है।",
            englishMeaning = "You are the imperishable, the supreme to be known. You are the ultimate resting place of this universe. You are the eternal protector of dharma, the timeless Person."
        ),
        Shloka(
            number = 19,
            sanskrit = "अनादिमध्यान्तमनन्तवीर्यमनन्तबाहुं शशिसूर्यनेत्रम् ।\nपश्यामि त्वां दीप्तहुताशवक्त्रं स्वतेजसा विश्वमिदं तपन्तम् ॥",
            hindiMeaning = "अर्जुन कहते हैं – मैं आपको देख रहा हूँ, जिनका न आरंभ है, न मध्य और न अंत। आपकी शक्ति अनंत है, भुजाएँ अनगिनत हैं। आपके नेत्र सूर्य और चंद्रमा के समान हैं। आपके मुख अग्नि की भाँति प्रज्वलित हैं, और आप अपने तेज से इस सम्पूर्ण जगत को दग्ध कर रहे हैं। यह श्लोक भगवान के विराट स्वरूप की अग्निमय और भयावह छवि प्रस्तुत करता है। अर्जुन को अब यह एहसास हो रहा है कि ईश्वर केवल सुन्दर और सौम्य ही नहीं, बल्कि प्रलयकारी शक्ति के भी धनी हैं। यह संदेश देता है कि ईश्वर सृष्टि के साथ-साथ संहार के भी नियंता हैं।",
            englishMeaning = "Without beginning, middle, or end, infinite in power, with countless arms, the sun and moon for eyes, blazing fire from Your mouth, You burn the universe with Your radiance."
        ),
        Shloka(
            number = 20,
            sanskrit = "द्यावापृथिव्योरिदमन्तरं हि व्याप्तं त्वयैकेन दिशश्च सर्वाः ।\nदृष्ट्वाद्भुतं रूपमुग्रं तवेदं लोकत्रयं प्रव्यथितं महात्मन् ॥",
            hindiMeaning = "अर्जुन कहते हैं – हे महात्मन्! आप एक ही शरीर से आकाश और पृथ्वी के बीच का स्थान और सब दिशाओं को व्याप्त किए हुए हैं। आपके इस अद्भुत और उग्र रूप को देखकर तीनों लोक भय से व्याकुल हो रहे हैं। यह श्लोक दर्शाता है कि भगवान का विराट रूप न केवल आश्चर्यजनक है बल्कि भयावह भी है। देवता, असुर और मनुष्य – सभी इस रूप को देखकर काँप उठते हैं। इससे यह शिक्षा मिलती है कि ईश्वर का स्वरूप केवल करुणा और प्रेम का ही प्रतीक नहीं, बल्कि उनकी शक्ति सभी के भीतर भय और विनम्रता भी उत्पन्न करती है।",
            englishMeaning = "O Great One, You alone pervade the space between heaven and earth and all directions. Seeing this wondrous and fierce form, the three worlds tremble."
        ),
        Shloka(
            number = 21,
            sanskrit = "अमी हि त्वां सुरसङ्घा विशन्ति केचिद्भीताः प्राञ्जलयो गृणन्ति ।\nस्वस्तीत्युक्त्वा महर्षिसिद्धसङ्घाः स्तुवन्ति त्वां स्तुतिभिः पुष्कलाभिः ॥",
            hindiMeaning = "अर्जुन कहते हैं – मैं देख रहा हूँ कि देवताओं के समूह आपके भीतर प्रवेश कर रहे हैं। कुछ भयभीत होकर हाथ जोड़कर आपकी स्तुति कर रहे हैं। महर्षि और सिद्धजन 'स्वस्ति' कहकर आपको विविध स्तुतियों से गुणगान कर रहे हैं। यहाँ यह स्पष्ट किया जा रहा है कि ईश्वर के विराट रूप को देखकर देवता और ऋषि भी चकित और भयभीत हैं। वे अपनी श्रद्धा और भक्ति प्रकट कर रहे हैं। यह श्लोक हमें बताता है कि ईश्वर का स्वरूप इतना महान है कि सबसे ऊँचे लोकवासी भी उनकी स्तुति और प्रार्थना में लगे रहते हैं।",
            englishMeaning = "The hosts of gods enter into You; some, struck with fear, praise You with folded hands. The great sages and perfected beings glorify You with hymns."
        ),
        Shloka(
            number = 22,
            sanskrit = "रुद्रादित्या वसवो ये च साध्या विश्वेऽश्विनौ मरुतश्चोष्मपाश्च ।\nगन्धर्वयक्षासुरसिद्धसङ्घा वीक्षन्ते त्वां विस्मिताश्चैव सर्वे ॥",
            hindiMeaning = "अर्जुन कहते हैं – रुद्र, आदित्य, वसु, साध्य, विश्वेदेव, अश्विनीकुमार, मरुत, पितर, गंधर्व, यक्ष, असुर और सिद्धों के समूह सभी आपके इस अद्भुत रूप को देख रहे हैं और विस्मित हैं। यह श्लोक दिखाता है कि भगवान का विराट स्वरूप केवल मनुष्यों तक सीमित नहीं है। सभी लोकों के प्राणी, चाहे वे देव हों या असुर, सभी इस दृश्य से आश्चर्यचकित हैं। इससे यह शिक्षा मिलती है कि ईश्वर की शक्ति और विराटता सभी जगतों से परे है।",
            englishMeaning = "The Rudras, Adityas, Vasus, Sadhyas, Vishvedevas, Ashvins, Maruts, ancestors, Gandharvas, Yakshas, Asuras, and Siddhas—all gaze upon You in wonder."
        ),
        Shloka(
            number = 23,
            sanskrit = "रूपं महत्ते बहुवक्त्रनेत्रं महाबाहो बहुबाहूरुपादम् ।\nबहूदरं बहुदंष्ट्राकरालं दृष्ट्वा लोका व्यथितास्तथाहम् ॥",
            hindiMeaning = "अर्जुन कहते हैं – हे महाबाहो! आपके इस विराट रूप में अनेक मुख और नेत्र हैं, अनेक भुजाएँ, जांघें और पाँव हैं, अनेक उदर हैं और आपकी भयानक दाढ़ें हैं। इस रूप को देखकर सब लोक भय से व्याकुल हो रहे हैं और मैं भी व्याकुल हो रहा हूँ। यह श्लोक बताता है कि भगवान का विराट रूप मनुष्य की कल्पना से परे है। यह रूप अद्भुत भी है और भयानक भी। यहाँ अर्जुन स्वयं स्वीकार कर रहे हैं कि उनका मन भय से भर गया है। इससे यह शिक्षा मिलती है कि ईश्वर का अनुभव केवल आनन्द ही नहीं, बल्कि भय और विस्मय भी उत्पन्न करता है।",
            englishMeaning = "O mighty-armed, seeing Your great form with many mouths and eyes, with many arms, thighs, and feet, with many bellies, and with dreadful tusks, the worlds are terrified, and so am I."
        ),
        Shloka(
            number = 24,
            sanskrit = "नभःस्पृशं दीप्तमनेकवर्णं व्यात्ताननं दीप्तविशालनेत्रम् ।\nदृष्ट्वा हि त्वां प्रव्यथितान्तरात्मा धृतिं न विन्दामि शमं च विष्णो ॥",
            hindiMeaning = "अर्जुन कहते हैं – हे विष्णु! मैं आपके इस आकाश को स्पर्श करने वाले, दीप्तिमान, अनेक रंगों से युक्त, विशाल नेत्रों वाले और खुले मुख वाले स्वरूप को देखकर अत्यंत व्याकुल हो रहा हूँ। मेरा मन स्थिर नहीं हो रहा है और मुझे शांति नहीं मिल रही है। यह श्लोक अर्जुन की मानसिक अवस्था को दर्शाता है। अब तक वे आश्चर्य में थे, परंतु अब भय और घबराहट अधिक हो गई है। भगवान का विराट रूप उनकी सहनशक्ति से परे है। यह संदेश देता है कि परमात्मा की वास्तविकता का अनुभव मनुष्य की सीमाओं को तोड़ देता है।",
            englishMeaning = "O Vishnu, seeing Your blazing, many-colored, sky-touching form with gaping mouths and wide eyes, my inner self trembles. I find no steadiness or peace."
        ),
        Shloka(
            number = 25,
            sanskrit = "दंष्ट्राकरालानि च ते मुखानि दृष्ट्वैव कालानलसन्निभानि ।\nदिशो न जाने न लभे च शर्म प्रसीद देवेश जगन्निवास ॥",
            hindiMeaning = "अर्जुन कहते हैं – आपके भयानक दाढ़ों वाले मुख अग्नि की ज्वालाओं जैसे प्रतीत हो रहे हैं। उन्हें देखकर मैं दिशाओं को पहचान नहीं पा रहा हूँ और मुझे शांति नहीं मिल रही है। हे देवेश! हे जगन्निवास! कृपा करके मुझ पर दया कीजिए। यह श्लोक अर्जुन की विनती है। विराट रूप का भयंकर पक्ष उन्हें असह्य हो रहा है। वे भगवान से दया और करुणा की याचना कर रहे हैं। इससे यह शिक्षा मिलती है कि भक्त जब भयभीत हो जाता है, तब भी वह भगवान की शरण में जाकर उनकी कृपा की प्रार्थना करता है।",
            englishMeaning = "Seeing Your mouths with fearful tusks, blazing like fires of cosmic destruction, I cannot recognize directions, nor find peace. O Lord of gods, be gracious to me."
        ),
        Shloka(
            number = 26,
            sanskrit = "अमी च त्वां धृतराष्ट्रस्य पुत्राः सर्वे सहैवावनिपालसङ्घैः ।\nभीष्मो द्रोणः सूतपुत्रस्तथासौ सहास्मदीयैरपि योधमुख्यैः ॥",
            hindiMeaning = "अर्जुन कहते हैं – मैं देख रहा हूँ कि धृतराष्ट्र के सभी पुत्र अपने-अपने सैनिकों सहित आपके भीतर प्रवेश कर रहे हैं। भीष्म पितामह, द्रोणाचार्य, कर्ण और हमारे पक्ष के भी अनेक महान योद्धा आपके मुखों में जा रहे हैं। यह श्लोक अत्यंत महत्वपूर्ण है क्योंकि यहाँ अर्जुन देख रहे हैं कि विराट रूप में युद्ध का परिणाम पहले से ही निर्धारित है। सभी योद्धा भगवान के स्वरूप में समाहित होकर अपने अंत की ओर बढ़ रहे हैं। यह शिक्षा है कि मनुष्य सोचता है कि वह स्वयं कर्म करता है, परंतु वास्तव में सब ईश्वर की योजना का ही अंग है।",
            englishMeaning = "I see all the sons of Dhritarashtra, along with their kings, Bhishma, Drona, Karna, and our chief warriors as well, entering into You."
        ),
        Shloka(
            number = 27,
            sanskrit = "वक्त्राणि ते त्वरमाणा विशन्ति दंष्ट्राकरालानि भयानकानि ।\nकेचिद्विलग्ना दशनान्तरेषु सन्दृश्यन्ते चूर्णितैरुत्तमाङ्गैः ॥",
            hindiMeaning = "अर्जुन कहते हैं – वे सब आपके भयानक दाढ़ों वाले मुखों में बड़ी तेजी से प्रवेश कर रहे हैं। उनमें से कुछ योद्धा आपके दाँतों के बीच फँसकर अपने सिर चूर्णित करवाते दिखाई दे रहे हैं। यह दृश्य अर्जुन के लिए भयावह और असहनीय था। यहाँ युद्ध का वास्तविक रूप प्रकट हो रहा है – मृत्यु सबको अपने भीतर समेट रही है। भगवान का विराट रूप यह दिखा रहा है कि सब प्राणी अंततः मृत्यु की ओर बढ़ते हैं। यह श्लोक साधक को स्मरण कराता है कि संसार में कोई भी स्थायी नहीं है।",
            englishMeaning = "Rushing into Your fearful mouths with terrible tusks, some are seen caught between Your teeth, with their heads crushed to powder."
        ),
        Shloka(
            number = 28,
            sanskrit = "यथा नदीनां बहवोऽम्बुवेगाः समुद्रमेवाभिमुखा द्रवन्ति ।\nतथा तवामी नरलोकवीरा विशन्ति वक्त्राण्यभिविज्वलन्ति ॥",
            hindiMeaning = "अर्जुन कहते हैं – जैसे नदियों की धारा वेग से समुद्र की ओर जाती है, वैसे ही ये नरलोक के सभी महान योद्धा आपके प्रज्वलित मुखों में प्रवेश कर रहे हैं। यहाँ अर्जुन यह उपमा दे रहे हैं कि जैसे जल का प्रवाह स्वाभाविक रूप से समुद्र की ओर बढ़ता है, वैसे ही सभी योद्धाओं का अंत भी भगवान के विराट स्वरूप में ही होता है। यह श्लोक हमें यह शिक्षा देता है कि मृत्यु की ओर गति अपरिहार्य है, और सब प्राणी अंततः ईश्वर में ही विलीन होते हैं।",
            englishMeaning = "As many rushing rivers flow toward the sea, so do these heroes of the human world enter Your blazing mouths."
        ),
        Shloka(
            number = 29,
            sanskrit = "यथा प्रदीप्तं ज्वलनं पतङ्गा विशन्ति नाशाय समृद्धवेगाः ।\nतथैव नाशाय विशन्ति लोकास्तवापि वक्त्राणि समृद्धवेगाः ॥",
            hindiMeaning = "अर्जुन कहते हैं – जैसे पतंगे प्रज्वलित अग्नि में नाश के लिए वेग से प्रवेश करते हैं, वैसे ही ये सभी लोग आपके मुखों में नाश के लिए वेगपूर्वक प्रवेश कर रहे हैं। यहाँ अर्जुन ने मृत्यु की अनिवार्यता को दर्शाने के लिए अत्यंत सशक्त उपमा दी है। संसार के योद्धा और प्राणी पतंगों की तरह हैं जो अनजाने में विनाश की ओर भागते हैं। भगवान का विराट रूप इस सत्य को प्रकट करता है कि हर जीव अंततः मृत्यु को प्राप्त होता है। यह श्लोक साधक को स्मरण कराता है कि जीवन नश्वर है और सब कुछ ईश्वर की इच्छा से ही होता है।",
            englishMeaning = "As moths rush swiftly into a blazing fire to perish, so do these worlds rush into Your mouths with great speed for destruction."
        ),
        Shloka(
            number = 30,
            sanskrit = "लेलिह्यसे ग्रसमानः समन्ताल्लोकान्समग्रान्वदनैर्ज्वलद्भिः ।\nतेजोभिरापूर्य जगत्समग्रं भासस्तवोग्राः प्रतपन्ति विष्णो ॥",
            hindiMeaning = "अर्जुन कहते हैं – हे विष्णु! आप अपनी ज्वलंत मुखों से सभी लोकों को चारों ओर से निगल रहे हैं। आप अपनी प्रचंड ज्वालाओं से सम्पूर्ण जगत को भर रहे हैं और आपका भयानक तेज इस सबको दग्ध कर रहा है। यह श्लोक विराट रूप की चरम भयावहता को दर्शाता है। अर्जुन देख रहे हैं कि समस्त लोक भगवान के तेज में नष्ट हो रहे हैं। इससे यह शिक्षा मिलती है कि ईश्वर न केवल सृष्टि का आधार हैं, बल्कि प्रलय के भी स्वामी हैं। उनका तेज सम्पूर्ण ब्रह्मांड को भस्म कर देने में सक्षम है।",
            englishMeaning = "You lick up and devour all the worlds from every side with Your flaming mouths. Filling the universe with Your blazing radiance, You scorch it, O Vishnu."
        ),
        Shloka(
            number = 31,
            sanskrit = "आख्याहि मे को भवानुग्ररूपो नमोऽस्तु ते देववर प्रसीद।\n" +
                    "विज्ञातुमिच्छामि भवन्तमाद्यं न हि प्रजानामि तव प्रवृत्तिम्।",
            hindiMeaning = "अर्जुन भगवान से पूछते हैं – हे देवश्रेष्ठ! कृपया मुझे बताइए कि आप कौन हैं। आपका यह भयंकर और विस्मयकारी रूप देखकर मैं भयभीत हो रहा हूँ। यद्यपि मैं जानता हूँ कि आप ही सबके आद्य कारण हैं, फिर भी आपके इस अद्भुत स्वरूप का वास्तविक उद्देश्य मेरी समझ से परे है। मैं आपके स्वरूप का रहस्य और आपके कार्य का लक्ष्य जानना चाहता हूँ। अर्जुन की यह जिज्ञासा उसके गहन भक्तिभाव और शिष्यत्व को दर्शाती है। वह केवल दर्शन से संतुष्ट नहीं है, बल्कि उसके पीछे का सत्य भी समझना चाहता है। उसकी विनती इस बात का प्रमाण है कि सच्चा भक्त केवल श्रद्धालु ही नहीं, बल्कि जिज्ञासु भी होता है।",
            englishMeaning = "Arjuna humbly asks Krishna to reveal who He is in this terrifying form. Though he knows Krishna as the source of all, he seeks to understand the true purpose behind this dreadful manifestation."
        )
        ,
        Shloka(
            number = 32,
            sanskrit = "कालोऽस्मि लोकक्षयकृत् प्रवृद्धो लोकान्समाहर्तुमिह प्रवृत्तः।\n" +
                    "ऋतेऽपि त्वां न भविष्यन्ति सर्वे येऽवस्थिताः प्रत्यनीकेषु योधाः।",
            hindiMeaning = "भगवान श्रीकृष्ण कहते हैं – मैं काल हूँ, जो लोकों का संहार करने के लिए बढ़ा हूँ। यहाँ उपस्थित सभी योद्धा मेरे द्वारा पहले ही विनाश के लिए निश्चित किए जा चुके हैं। चाहे तुम युद्ध करो या न करो, वे नष्ट होने ही वाले हैं। अर्जुन को यहाँ यह शिक्षा दी जा रही है कि परमात्मा की योजना को कोई बदल नहीं सकता। काल रूपी भगवान सभी प्राणियों को अपने चक्र में समेट लेते हैं। मनुष्य केवल निमित्त बनता है, वास्तविक कर्ता तो ईश्वर ही है। यह शिक्षा अर्जुन को भय से मुक्त करने और उसके कर्तव्य पालन की ओर प्रेरित करने के लिए दी गई।",
            englishMeaning = "Krishna declares Himself to be Time, the great destroyer of worlds. All warriors standing here are already doomed, with or without Arjuna’s involvement. Divine will is inevitable."
        ),

        Shloka(
            number = 33,
            sanskrit = "तस्मात्त्वमुत्तिष्ठ यशो लभस्व जित्वा शत्रून् भुङ्क्ष्व राज्यं समृद्धम्।\n" +
                    "मयैवैते निहताः पूर्वमेव निमित्तमात्रं भव सव्यसाचिन्।",
            hindiMeaning = "भगवान कहते हैं – इसलिए हे सव्यसाची अर्जुन! उठो और यश प्राप्त करो। अपने शत्रुओं को जीतकर समृद्ध राज्य का भोग करो। वास्तव में ये सभी मेरे द्वारा पहले ही मारे जा चुके हैं। तुम तो केवल एक साधन बनो। यह उपदेश अर्जुन को यह समझाने के लिए है कि मनुष्य केवल कर्म का अधिकारी है, परिणाम का नहीं। अर्जुन को यह जानकर निःशंक होना चाहिए कि उसकी विजय सुनिश्चित है। उसे केवल धर्म की रक्षा के लिए अपना कर्तव्य निभाना है।",
            englishMeaning = "Krishna urges Arjuna to rise, gain glory, and conquer his enemies. These warriors are already slain by Krishna; Arjuna is only an instrument in the divine plan."
        ),

        Shloka(
            number = 34,
            sanskrit = "द्रोणं च भीष्मं च जयद्रथं च कर्णं तथान्यानपि योधवीरान्।\n" +
                    "मया हतांस्त्वं जहि मा व्यथिष्ठा युध्यस्व जेतासि रणे सपत्नान्।",
            hindiMeaning = "भगवान अर्जुन से कहते हैं – द्रोणाचार्य, भीष्म पितामह, जयद्रथ और कर्ण जैसे महान योद्धा तथा अन्य वीर भी मेरे द्वारा पहले ही मारे जा चुके हैं। तुम केवल युद्ध करके इनको परास्त करो। भयभीत मत हो, तुम निश्चित ही अपने शत्रुओं को युद्ध में जीतोगे। यह शिक्षा अर्जुन को स्पष्ट करती है कि उसकी भूमिका केवल एक धर्मयुद्ध योद्धा की है। उसके शत्रु पहले ही कालचक्र में समाप्त हो चुके हैं। भगवान उसे आत्मविश्वास दिला रहे हैं कि विजय निश्चित है।",
            englishMeaning = "Krishna tells Arjuna that Bhishma, Drona, Karna, Jayadratha, and other warriors are already slain by Him. Arjuna should fight without fear, for victory is assured."
        ),

        Shloka(
            number = 35,
            sanskrit = "सञ्जय उवाच।\n" +
                    "एतच्छ्रुत्वा वचनं केशवस्य कृताञ्जलिर्वेपमानः किरीटी।\n" +
                    "नमस्कृत्वा भूय एवाह कृष्णं सगद्गदं भीतभीतः प्रणम्य।",
            hindiMeaning = "संजय धृतराष्ट्र से कहते हैं – भगवान के ये वचन सुनकर अर्जुन अत्यंत भयभीत हो गया। उसका शरीर कांपने लगा, उसने हाथ जोड़कर कृष्ण को प्रणाम किया। उसकी वाणी गद्गद हो गई और वह गहरे भय और भक्ति के भाव से पुनः भगवान की स्तुति करने लगा। यह दृश्य दर्शाता है कि विराट रूप का दर्शन अर्जुन के लिए कितना अद्भुत और भयावह था। उसका मन भक्ति और विस्मय से भर गया था। अर्जुन इस स्थिति में भक्त और शिष्य दोनों रूपों में था।",
            englishMeaning = "Sanjaya narrates that after hearing Krishna’s words, Arjuna, trembling and overwhelmed with fear, bowed down with folded hands. His voice choked with devotion as he again addressed Krishna."
        ),

        Shloka(
            number = 36,
            sanskrit = "अर्जुन उवाच।\n" +
                    "स्थाने हृषीकेश तव प्रकीर्त्या जगत्प्रहृष्यत्यनुरज्यते च।\n" +
                    "रक्षांसि भीतानि दिशो द्रवन्ति सर्वे नमस्यन्ति च सिद्धसङ्घाः।",
            hindiMeaning = "अर्जुन भगवान से कहता है – हे हृषीकेश! यह स्वाभाविक है कि आपके नाम और कीर्तनों को सुनकर संपूर्ण जगत आनंदित होता है और आपकी ओर आकर्षित होता है। राक्षस भयभीत होकर इधर-उधर भागते हैं और सिद्धजन आपको नमस्कार करते हैं। आपके स्वरूप की महिमा अद्वितीय है। यह बताता है कि ईश्वर के नाम और गुणों का प्रभाव सभी पर पड़ता है – भक्तजन प्रेम से आकर्षित होते हैं, दुष्ट भयभीत हो जाते हैं। अर्जुन इस विराट रूप की सार्वभौमिक स्वीकृति को स्वीकार कर रहा है।",
            englishMeaning = "Arjuna says that it is natural the world rejoices on hearing Krishna’s glories. Demons flee in fear, while the hosts of perfected beings bow down before Him."
        ),

        Shloka(
            number = 37,
            sanskrit = "कस्माच्च ते न नमेरन्महात्मन् गरीयसे ब्रह्मणोऽप्यादिकर्त्रे।\n" +
                    "अनन्त देवेश जगन्निवास त्वमक्षरं सदसत्तत्परं यत्।",
            hindiMeaning = "अर्जुन आगे कहता है – हे महानात्मा! भला कौन आपको नमस्कार न करेगा? आप तो ब्रह्मा से भी आदिकर्ता हैं। हे अनंत! हे देवेश! हे जगन्निवास! आप ही शाश्वत हैं, आप सत-असत से भी परे हैं। यह श्लोक ईश्वर की सर्वोच्च सत्ता को प्रकट करता है। अर्जुन कह रहा है कि आप समस्त सृष्टि के मूल कारण और सभी देवताओं के स्वामी हैं। आपके अतिरिक्त कोई भी शक्ति स्वतंत्र रूप से विद्यमान नहीं है।",
            englishMeaning = "Arjuna praises Krishna as the Supreme Lord, the origin of even Brahma, the eternal and infinite refuge of the universe, beyond both existence and non-existence."
        ),

        Shloka(
            number = 38,
            sanskrit = "त्वमादिदेवः पुरुषः पुराणस्त्वमस्य विश्वस्य परं निधानम्।\n" +
                    "वेत्तासि वेद्यं च परं च धाम त्वया ततं विश्वमनन्तरूप।",
            hindiMeaning = "अर्जुन कहता है – आप ही आदि देव हैं, आप ही सनातन पुरुष हैं। आप इस पूरे विश्व का परम आधार हैं। आप ही सब कुछ जानने योग्य हैं और आप ही परम धाम हैं। हे अनन्तरूप! यह सारा जगत आपसे ही व्याप्त है। यह वर्णन ईश्वर की सर्वव्यापकता और सर्वज्ञता को दर्शाता है। अर्जुन स्वीकार करता है कि परमात्मा ही सभी ज्ञान का लक्ष्य और सभी प्राणियों का आधार हैं। उसका विश्वास और भक्ति अब पूर्ण हो चुकी है।",
            englishMeaning = "Arjuna acknowledges Krishna as the primal God, the eternal being, and the supreme foundation of the universe. He is the ultimate object of knowledge and the all-pervading form."
        ),

        Shloka(
            number = 39,
            sanskrit = "वायुर्यमोऽग्निर्वरुणः शशाङ्कः प्रजापतिस्त्वं प्रपितामहश्च।\n" +
                    "नमो नमस्तेऽस्तु सहस्रकृत्वः पुनश्च भूयोऽपि नमो नमस्ते।",
            hindiMeaning = "अर्जुन कहता है – आप ही वायु हैं, यम हैं, अग्नि हैं, वरुण हैं, चंद्रमा हैं, प्रजापति हैं और प्रपितामह ब्रह्मा भी आप ही हैं। मैं आपको बार-बार नमस्कार करता हूँ, सहस्र बार प्रणाम करता हूँ। हे प्रभु! आप ही सब रूपों में विद्यमान हैं। यह श्लोक ईश्वर की सर्वरूपता को प्रकट करता है। अर्जुन स्वीकार करता है कि हर देवता और शक्ति वास्तव में ईश्वर के ही अंश हैं। उसकी वाणी भक्ति और श्रद्धा से ओतप्रोत हो उठी है।",
            englishMeaning = "Arjuna proclaims Krishna to be Vayu, Yama, Agni, Varuna, the Moon, Prajapati, and Brahma. He bows again and again, offering countless salutations to the Lord in all forms."
        ),

        Shloka(
            number = 40,
            sanskrit = "नमः समस्ताभूतसद्भाविताय नमोऽस्तु तेऽनन्तमहाविभूतये।\n" +
                    "सर्वं समाप्नोषि ततोऽसि सर्वः।",
            hindiMeaning = "अर्जुन कहता है – उन सब भूतों के कारणभूत आपको नमस्कार है। हे अनंत, हे महान विभूतियों वाले प्रभु, आपको बार-बार प्रणाम है। आप ही सबको समेटते हैं, इसलिए आप ही सब कुछ हैं। यह श्लोक ईश्वर की अनंत शक्तियों और सर्वसमावेशी स्वरूप का वर्णन करता है। अर्जुन स्वीकार करता है कि सारा अस्तित्व उसी ईश्वर का विस्तार है। उसका समर्पण अब पूर्ण हो चुका है।",
            englishMeaning = "Arjuna bows to Krishna as the cause of all beings, the infinite Lord of great powers. Since Krishna encompasses everything, He Himself is everything."
        ),

        Shloka(
            number = 41,
            sanskrit = "सखेति मत्वा प्रसभं यदुक्तं हे कृष्ण हे यादव हे सखेति।\n" +
                    "अजानता महिमानं तवेदं मया प्रमादात्प्रणयेन वापि।",
            hindiMeaning = "अर्जुन विनम्र होकर कहता है – हे कृष्ण! आपको मित्र मानकर मैंने कभी 'हे कृष्ण, हे यादव, हे सखे' कहकर अनायास ही संबोधित किया था। उस समय मैं आपकी महिमा से अनजान था। कभी मजाक में, कभी प्रेम में और कभी असावधानीवश मैंने ऐसा किया। अब जब मैं आपका यह विराट रूप देख रहा हूँ, तो मुझे अपनी उन बातों पर खेद हो रहा है। यह श्लोक अर्जुन की विनम्रता और आत्मग्लानि को प्रकट करता है।",
            englishMeaning = "Arjuna apologizes to Krishna, saying he addressed Him casually as a friend in ignorance of His greatness. Out of familiarity and affection, he had spoken without realizing Krishna’s divine majesty."
        ),

        Shloka(
            number = 42,
            sanskrit = "यच्चावहासार्थमसत्कृतोऽसि विहारशय्यासनभोजनेषु।\n" +
                    "एकोऽथवाप्यच्युत तत्समक्षं तत्क्षामये त्वामहमप्रमेयम्।",
            hindiMeaning = "अर्जुन कहता है – और यदि कभी मैंने खेल में, विश्राम में, बैठने या भोजन करने के समय अकेले में अथवा साथियों के सामने आपको असम्मानपूर्वक संबोधित किया हो, तो हे अच्युत! मैं आपसे उसके लिए क्षमा चाहता हूँ। आप अपरिमेय हैं, आपकी महिमा को समझना मनुष्य के लिए असंभव है। इसलिए मैं अपनी त्रुटियों के लिए आपसे क्षमा प्रार्थना करता हूँ। यह श्लोक अर्जुन की गहन पश्चाताप और समर्पण को दर्शाता है।",
            englishMeaning = "Arjuna seeks forgiveness for any disrespect he may have shown Krishna, in play, rest, eating, or in company. He admits Krishna is immeasurable and asks pardon for his past familiarity."
        ),

        Shloka(
            number = 43,
            sanskrit = "पितासि लोकस्य चराचरस्य त्वमस्य पूज्यश्च गुरुर्गरीयान्।\n" +
                    "न त्वत्समोऽस्त्यभ्यधिकः कुतोऽन्यो लोकत्रयेऽप्यप्रतिमप्रभाव।",
            hindiMeaning = "अर्जुन कहता है – आप ही इस समस्त चराचर जगत के पिता हैं। आप ही पूज्य हैं और आप ही सबसे महान गुरु हैं। तीनों लोकों में न तो आपका कोई समकक्ष है और न ही कोई आपसे श्रेष्ठ हो सकता है। आपकी महिमा अप्रतिम है। यह श्लोक ईश्वर की सर्वोच्च सत्ता और अद्वितीयता को प्रकट करता है। अर्जुन अब पूरी तरह से भगवान के परम स्वरूप को स्वीकार कर चुका है।",
            englishMeaning = "Arjuna acknowledges Krishna as the father of the universe, the most worshipful and greatest teacher. No one equals or surpasses Him in all the three worlds."
        ),

        Shloka(
            number = 44,
            sanskrit = "तस्मात्प्रणम्य प्रणिधाय कायं प्रसादये त्वामहमीशमीड्यम्।\n" +
                    "पितेव पुत्रस्य सखेव सख्युः प्रियः प्रियायार्हसि देव सोढुम्।",
            hindiMeaning = "अर्जुन कहता है – इसलिए मैं अपने शरीर को आपके आगे झुकाकर आपको प्रणाम करता हूँ और आपसे कृपा की याचना करता हूँ। हे प्रभु! जैसे पिता अपने पुत्र की भूल को सह लेता है, जैसे मित्र अपने मित्र की गलती को बर्दाश्त करता है, और जैसे प्रिय अपने प्रियतम की त्रुटि को सह लेता है, वैसे ही आप भी मेरी त्रुटियों को क्षमा करें। यह श्लोक अर्जुन के समर्पण और भगवान से करुणा की याचना को दर्शाता है।",
            englishMeaning = "Arjuna bows his body before Krishna, asking for mercy. He pleads that Krishna forgive him as a father forgives his son, a friend forgives a friend, or a lover forgives the beloved."
        ),

        Shloka(
            number = 45,
            sanskrit = "अदृष्टपूर्वं हृषितोऽस्मि दृष्ट्वा भयेन च प्रव्यथितं मनो मे।\n" +
                    "तदेव मे दर्शय देव रूपं प्रसीद देवेश जगन्निवास।",
            hindiMeaning = "अर्जुन कहता है – हे देवेश! मैंने आपका ऐसा स्वरूप पहले कभी नहीं देखा था। इसे देखकर मैं आनंदित भी हुआ और साथ ही अत्यधिक भयभीत भी हो गया। अब कृपया मुझ पर कृपा करें और अपना वही सौम्य रूप दिखाएँ। हे जगन्निवास! मैं आपसे विनती करता हूँ कि मुझे शांति प्रदान करें। यह श्लोक दर्शाता है कि विराट रूप का दर्शन अर्जुन के लिए आश्चर्य और भय दोनों का कारण बना। वह अब भगवान से उनके प्रिय और शांति देने वाले रूप की याचना करता है।",
            englishMeaning = "Arjuna admits he has never seen such a form before. Though thrilled, his mind is shaken with fear, and he requests Krishna to show him His gentle form again."
        ),
        Shloka(
            number = 46,
            sanskrit = "किरीटिनं गदिनं चक्रहस्तं इच्छामि त्वां द्रष्टुमहं तथैव। तेनैव रूपेण चतुर्भुजेन सहस्रबाहो भव विश्वमूर्ते॥",
            hindiMeaning = "अर्जुन कहते हैं – हे सहस्रबाहु! मैं आपको आपके उस रूप में देखना चाहता हूँ जिसमें आप किरीटधारी हैं, गदा और चक्र धारण किए हुए हैं और चार भुजाओं से युक्त हैं। आपकी यह विराट विश्वरूप ने मेरे हृदय में भय और विस्मय उत्पन्न किया है, अब मैं आपके सौम्य और सुहावने रूप का दर्शन करना चाहता हूँ। अर्जुन यहाँ भगवान से प्रार्थना करते हैं कि वे अपने सहज और प्रिय रूप में प्रकट हों। यह मनुष्य की स्वाभाविक प्रवृत्ति है कि वह अपने ईश्वर को ऐसा देखना चाहता है जो भयभीत न करे बल्कि स्नेह और शांति प्रदान करे। अर्जुन की यह विनती भक्त और भगवान के आत्मीय संबंध को व्यक्त करती है।",
            englishMeaning = "Arjuna requests Krishna to show His gentle form again—crowned, holding the mace and discus, with four arms. After witnessing the terrifying universal form, he longs for the comforting, familiar divine appearance."
        ),

        Shloka(
            number = 47,
            sanskrit = "श्रीभगवानुवाच। मया प्रसन्नेन तवार्जुनैदं रूपं परं दर्शितमात्मयोगात्। तेजोमयं विश्वमनन्तमाद्यं यन्मे त्वदन्येन न दृष्टपूर्वम्॥",
            hindiMeaning = "भगवान श्रीकृष्ण कहते हैं – हे अर्जुन! मेरी प्रसन्नता के कारण ही मैंने तुम्हें अपने इस परम, तेजोमय, अनंत और आदि रूप का दर्शन कराया है। यह विश्वव्यापी रूप किसी और ने कभी पहले नहीं देखा। केवल तुम्हारे प्रति अनुग्रहवश मैंने यह अद्भुत रूप प्रकट किया है। भगवान यहाँ यह स्पष्ट करते हैं कि ऐसा दिव्य अनुभव केवल ईश्वर की कृपा से ही संभव है, न कि साधारण मानवीय प्रयास से। अर्जुन की भक्ति और निष्ठा के कारण ही उन्हें यह सौभाग्य प्राप्त हुआ है।",
            englishMeaning = "Krishna tells Arjuna that by His grace alone he has been allowed to see this supreme, infinite, radiant form. No one before has ever witnessed it. It is a rare vision granted only by divine favor."
        ),

        Shloka(
            number = 48,
            sanskrit = "न वेदयज्ञाध्ययनैर्न दानैः न च क्रियाभिर्न तपोभिरुग्रैः। एवंरूपः शक्य अहं नृलोके द्रष्टुं त्वदन्येन कुरुप्रवीर॥",
            hindiMeaning = "भगवान कहते हैं – हे कुरुप्रवीर! इस रूप को न वेदों के अध्ययन से, न यज्ञों से, न दान देने से, न ही कठोर तप से देखा जा सकता है। मनुष्यों के लोक में कोई भी इस रूप का दर्शन नहीं कर सकता, केवल तुम ही इसके अधिकारी हो। यह बात अर्जुन को यह समझाने के लिए कही गई कि भगवान का सच्चा दर्शन केवल भक्तिपूर्ण समर्पण से संभव है, न कि मात्र कर्मकांड या कठोर साधनाओं से। ईश्वर के विराट स्वरूप को प्राप्त करने के लिए साधन से अधिक भक्ति और कृपा का महत्व है।",
            englishMeaning = "Krishna explains that this form cannot be seen through study of the Vedas, sacrifices, charity, or severe austerities. No one in the human world has seen it—only Arjuna has been granted this rare vision."
        ),

        Shloka(
            number = 49,
            sanskrit = "मा ते व्यथा मा च विमूढभावो दृष्ट्वा रूपं घोरमीदृङ्ममेदम्। व्यपेतभीः प्रीतमनाः पुनस्त्वं तदेव मे रूपमिदं प्रपश्य॥",
            hindiMeaning = "भगवान कहते हैं – मेरे इस भयंकर रूप को देखकर तुम्हें जो व्यथा और भ्रम हुआ है, उसकी अब आवश्यकता नहीं है। भय को छोड़कर, प्रसन्न मन से तुम फिर से मेरे उसी शांत और सुन्दर रूप का दर्शन करो। यहाँ भगवान अर्जुन को आश्वासन देते हैं कि उनकी भक्ति और प्रेम का उत्तर सौम्य और करुणामय रूप से दिया जाएगा। विश्वरूप केवल यह दिखाने के लिए था कि ईश्वर की शक्ति और विराटता कैसी है, परंतु वास्तविक अनुभव में भक्त को भगवान का सौम्य और स्नेहपूर्ण रूप ही प्रिय होता है।",
            englishMeaning = "Krishna consoles Arjuna, telling him not to be disturbed or confused by seeing the terrible form. He asks him to be free of fear and behold again His calm, gentle, and pleasing form."
        ),

        Shloka(
            number = 50,
            sanskrit = "सञ्जय उवाच। इत्यर्जुनं वासुदेवस्तथोक्त्वा स्वकं रूपं दर्शयामास भूयः। आश्वासयामास च भीतमेनं भूत्वा पुनः सौम्यवपुर्महात्मा॥",
            hindiMeaning = "संजय धृतराष्ट्र से कहते हैं – इस प्रकार वासुदेव भगवान श्रीकृष्ण ने अर्जुन को समझाकर अपना सौम्य रूप पुनः दिखाया। उन्होंने अपने महात्मा स्वरूप से भयभीत अर्जुन को आश्वस्त किया और अपनी सुन्दर और शांत मूर्ति का दर्शन कराया। यह वर्णन यह दर्शाता है कि ईश्वर अपने भक्त की मनःस्थिति के अनुसार अपना रूप प्रकट करते हैं। जब भक्त भयभीत होता है, तो वे करुणा और शांति का रूप धारण कर उसके मन को स्थिर करते हैं।",
            englishMeaning = "Sanjaya narrates that after speaking thus, Krishna showed His normal gentle form again and comforted the frightened Arjuna with His calm, beautiful appearance."
        ),

        Shloka(
            number = 51,
            sanskrit = "अर्जुन उवाच। दृष्ट्वेदं मानुषं रूपं तव सौम्यं जनार्दन। इदानीमस्मि संवृत्तः सचेताः प्रकृतिं गतः॥",
            hindiMeaning = "अर्जुन कहते हैं – हे जनारन! अब आपके इस मानव-सदृश सौम्य रूप को देखकर मैं शांत और प्रसन्न हो गया हूँ। मेरा चित्त स्थिर हो गया है और मैं अपनी स्वाभाविक अवस्था में लौट आया हूँ। अर्जुन यहाँ यह स्वीकार करते हैं कि भगवान का मानवीय रूप ही उनके लिए प्रिय और सुखद है, क्योंकि उसमें स्नेह, करुणा और आत्मीयता झलकती है। भयावह विश्वरूप दर्शन के बाद यह सौम्य रूप अर्जुन को मानसिक शांति और आश्रय प्रदान करता है।",
            englishMeaning = "Arjuna says that after seeing Krishna’s gentle human-like form, his mind has become calm and composed again. He feels restored to his natural state."
        ),

        Shloka(
            number = 52,
            sanskrit = "श्रीभगवानुवाच। सुदुर्दर्शमिदं रूपं दृष्टवानसि यन्मम। देवा अप्यस्य रूपस्य नित्यं दर्शनकाङ्क्षिणः॥",
            hindiMeaning = "भगवान श्रीकृष्ण कहते हैं – तुमने जो मेरा यह रूप देखा है, वह अत्यंत दुर्लभ है। देवता भी सदा इस रूप को देखने की आकांक्षा रखते हैं। यह स्पष्ट करता है कि भगवान का विराट और दिव्य स्वरूप केवल विशेष कृपा से ही देखा जा सकता है। यह साधारण मनुष्यों या यहाँ तक कि देवताओं के लिए भी सहज उपलब्ध नहीं है। इससे यह भी शिक्षा मिलती है कि ईश्वर का सच्चा दर्शन केवल अनन्य भक्ति और उनकी कृपा से संभव होता है।",
            englishMeaning = "Krishna tells Arjuna that the form he has seen is very rare. Even the gods constantly long to behold it. Such a vision is not easily available to anyone."
        ),

        Shloka(
            number = 53,
            sanskrit = "नाहं वेदैर्न तपसा न दानेन न चेज्यया। शक्य एवंविधो द्रष्टुं दृष्टवानसि मां यथा॥",
            hindiMeaning = "भगवान कहते हैं – न तो वेदों के अध्ययन से, न कठोर तप से, न दान देने से और न ही यज्ञ करने से मुझे इस रूप में देखा जा सकता है जैसा तुमने देखा है। यह बताता है कि केवल बाह्य धार्मिक क्रियाएँ पर्याप्त नहीं हैं। ईश्वर का साक्षात्कार केवल गहन भक्ति और उनकी अनुकंपा से ही संभव है। शास्त्र, यज्ञ और दान केवल साधन हैं, परंतु सच्चे दर्शन का आधार केवल समर्पण और प्रेम है।",
            englishMeaning = "Krishna explains that He cannot be seen in this form through study of the Vedas, austerities, charity, or rituals. The vision Arjuna received is possible only by divine grace."
        ),

        Shloka(
            number = 54,
            sanskrit = "भक्त्या त्वनन्यया शक्य अहमेवंविधोऽर्जुन। द्रष्टुं द्रष्टुमिच्छन्तोऽपि न तु वेदाः प्रपन्ति॥",
            hindiMeaning = "भगवान कहते हैं – हे अर्जुन! केवल अनन्य भक्ति द्वारा ही मुझे इस प्रकार के रूप में देखा जा सकता है। यद्यपि वेद और अन्य साधन मुझे पाने का प्रयास करते हैं, परंतु वास्तविक दर्शन केवल निष्काम और एकनिष्ठ भक्ति से ही संभव है। यहाँ भगवान यह शिक्षा देते हैं कि भक्ति मार्ग ही सर्वोच्च मार्ग है। भक्ति में जब पूर्ण समर्पण होता है, तब ही ईश्वर अपने स्वरूप का साक्षात्कार कराते हैं।",
            englishMeaning = "Krishna reveals that He can be truly seen in this way only through undivided devotion. The Vedas and other practices alone cannot lead to such vision—pure devotion is the key."
        ),

        Shloka(
            number = 55,
            sanskrit = "मत्कर्मकृन्मत्परमो मद्भक्तः सङ्गवर्जितः। निर्वैरः सर्वभूतेषु यः स मामेति पाण्डव॥",
            hindiMeaning = "भगवान अंतिम उपदेश में कहते हैं – हे पाण्डव! जो मनुष्य मेरा कार्य करता है, मुझे ही परम मानता है, अनन्य भक्ति रखता है, आसक्ति से रहित है और सभी प्राणियों के प्रति वैरभाव से मुक्त है – वही वास्तव में मुझे प्राप्त करता है। इस श्लोक में भक्ति योग का सार प्रस्तुत किया गया है। ईश्वर का साक्षात्कार केवल कर्म, ज्ञान या तप से नहीं, बल्कि कर्म करते हुए अनन्य प्रेम, समर्पण और निष्कामता से होता है। जब भक्त संसारिक आसक्तियों और द्वेष से मुक्त होकर केवल ईश्वर को सर्वोच्च मानता है, तब वह परम सत्य को प्राप्त करता है।",
            englishMeaning = "Krishna concludes that one who works for Him, considers Him the supreme goal, devotes himself with pure love, is free from attachment, and bears no hatred toward any being—such a person truly reaches Him."
        ),

        )
    private val adhyayaFifteenShlokas = listOf(
